export type PageType = 'home' | 'events' | 'amenities' | 'directory' | 'forum' | 'ai' | 'admin' | 'messaging';

export interface Announcement {
  id: string;
  title: string;
  content: string;
  category: 'News' | 'Maintenance' | 'Board';
  date: string;
  isPinned?: boolean;
}

export interface Event {
  id: string;
  title: string;
  date: string;
  time: string;
  location: string;
  category: 'Social' | 'Sports' | 'Meeting';
  description: string;
  capacity: number;
  rsvps: number;
}

export interface Amenity {
  id: string;
  name: string;
  icon: string;
  hours: string;
  rules: string[];
  image: string;
}

export interface Resident {
  id: string;
  name: string;
  avatar: string;
  points: number;
  messagingEnabled: boolean;
  interests: string[];
}

export interface ForumTopic {
  id: string;
  title: string;
  author: string;
  replies: number;
  lastActivity: string;
  category: string;
}

export interface ChatMessage {
  id: string;
  sender: 'user' | 'ai' | 'resident';
  text: string;
  timestamp: Date;
}

