import { GoogleGenAI } from "@google/genai";
import { MOCK_ANNOUNCEMENTS, MOCK_EVENTS, MOCK_AMENITIES, MOCK_FAQS, MOCK_RULES } from "../constants";

const getSystemInstruction = () => {
  const context = `
    You are the Polo Park East AI Concierge. 
    You only answer questions about the Polo Park East 55+ Golf Community.

    Current Community Data:
    Announcements: ${JSON.stringify(MOCK_ANNOUNCEMENTS)}
    Events: ${JSON.stringify(MOCK_EVENTS)}
    Amenities: ${JSON.stringify(MOCK_AMENITIES)}
    Common FAQs: ${JSON.stringify(MOCK_FAQS)}
    Community Rules: ${JSON.stringify(MOCK_RULES)}

    Rules for you:
    1. Be polite, warm, and helpful to seniors.
    2. Deflect any medical, legal, or emergency questions. Tell them to call 911 for emergencies or visit the main office for legal/medical advice.
    3. If you don't know the answer based on the data provided, ask them to contact the community board at (555) 123-4567.
    4. Keep answers concise.
    5. Always refer to current community rules and hours when asked.
  `;
  return context;
};

export const chatWithAI = async (message: string) => {
  if (!process.env.API_KEY) return "API Key not configured.";

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: message,
      config: {
        systemInstruction: getSystemInstruction(),
        temperature: 0.7,
      }
    });
    return response.text || "I'm sorry, I couldn't process that request.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "The concierge is currently offline. Please try again later.";
  }
};

