                >
                  {hint}
                </button>
              ))}
            </div>

            <div className="p-2 bg-white border border-border rounded-2xl flex items-center space-x-2 shadow-lg">
              <input 
                type="text" 
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Ask about hours, rules, or events..." 
                className="flex-1 bg-transparent border-none focus:outline-none px-2 py-2 text-sm"
              />
              <button 
                onClick={handleSendMessage}
                className="p-2 bg-gold text-navy rounded-xl hover:bg-goldPressed transition-all"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
            </div>
            <p className="text-[10px] text-slate-400 mt-2 text-center uppercase tracking-widest font-bold">Grounded in Community Rules & FAQs</p>
          </div>
        );

      case 'notifications':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <SectionHeader title="Notifications" subtitle="Stay in the loop" />
              <button onClick={markAllRead} className="text-xs font-bold text-gold uppercase tracking-widest">Mark all as read</button>
            </div>
            <div className="space-y-3">
              {notifications.length === 0 ? (
                <div className="py-20 text-center text-slate-400">
                  <ICONS.Bell />
                  <p className="mt-2 text-sm">No new notifications</p>
                </div>
              ) : (
                notifications.map(notif => (
                  <Card key={notif.id} className={`flex items-start space-x-4 ${!notif.read ? 'border-l-4 border-l-gold' : ''}`}>
                    <div className={`p-3 rounded-xl ${notif.type === 'event' ? 'bg-amber-50 text-amber-600' : 'bg-blue-50 text-blue-600'}`}>
                      {notif.type === 'event' ? <ICONS.Calendar /> : <ICONS.Announcement />}
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between items-center mb-1">
                        <h4 className="font-bold text-navy">{notif.title}</h4>
                        <span className="text-[10px] text-slate-400 uppercase font-bold">Just Now</span>
                      </div>
                      <p className="text-xs text-bodyText">{notif.message}</p>
                    </div>
                  </Card>
                ))
              )}
            </div>
          </div>
        );

      case 'admin':
        if (!adminAuth) {
          return (
            <div className="max-w-md mx-auto py-20 text-center">
              <Title>Admin Login</Title>
              <form onSubmit={(e) => {
                e.preventDefault();
                const code = (new FormData(e.currentTarget)).get('pass') as string;
                if (code === ADMIN_PASSCODE) setAdminAuth(true);
                else alert('Wrong passcode');
              }}>
                <input name="pass" type="password" placeholder="Passcode" className="w-full p-4 rounded-xl border border-border mb-4 text-center" />
                <Button className="w-full">Unlock Dashboard</Button>
              </form>
            </div>
          );
        }
        return (
          <div className="space-y-6">
             <SectionHeader title="Admin Dashboard" subtitle="Manage community knowledge" />
             <div className="grid grid-cols-2 gap-4">
                {[
                  { label: 'Broadcast Notif', action: () => alert("Notification sent to all residents") },
                  { label: 'Edit Knowledge Base', action: () => alert("Knowledge base updated for AI") },
                  { label: 'Manage Events', action: () => setActivePage('events') },
                  { label: 'Reports', action: () => alert("No reports active") }
                ].map(item => (
                  <Card key={item.label} className="py-8 flex flex-col items-center text-center cursor-pointer hover:bg-goldTint" onClick={item.action}>
                    <span className="font-bold text-navy text-sm">{item.label}</span>
                    <button className="text-[10px] text-gold font-bold mt-2 uppercase">Open →</button>
                  </Card>
                ))}
             </div>
             <Button variant="outline" className="w-full" onClick={() => setAdminAuth(false)}>Logout</Button>
          </div>
        );

      default:
        return <div>Page coming soon...</div>;
    }
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <Layout activePage={activePage} setActivePage={setActivePage} isGated={isGated} unreadCount={unreadCount}>
      {renderContent()}
    </Layout>
  );
};

export default App;

