const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageType>('home');
  const [isGated, setIsGated] = useState<boolean>(!localStorage.getItem('ppe_auth'));
  const [adminAuth, setAdminAuth] = useState<boolean>(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'ai', text: 'Hello! I am your Polo Park East Concierge. How can I help you today?', timestamp: new Date() }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isPopoutOpen, setIsPopoutOpen] = useState(false);
  const popoutScrollRef = useRef<HTMLDivElement>(null);

  // Notification State
  const [notifications, setNotifications] = useState<AppNotification[]>([
    { id: '1', title: 'New Event!', message: 'Pickleball Mixer has been added for next Saturday.', type: 'event', timestamp: new Date(), read: false },
    { id: '2', title: 'Maintenance Alert', message: 'Pool closing reminder for Oct 10th.', type: 'announcement', timestamp: new Date(), read: false }
  ]);
  const [notifSettings, setNotifSettings] = useState<NotificationSettings>({
    announcements: true,
    events: true,
    messages: false
  });

  // Auto-scroll for chat
  useEffect(() => {
    if (activePage === 'ai') {
      const el = document.getElementById('chat-scroll');
      if (el) el.scrollTop = el.scrollHeight;
    }
    if (isPopoutOpen && popoutScrollRef.current) {
      popoutScrollRef.current.scrollTop = popoutScrollRef.current.scrollHeight;
    }
  }, [messages, activePage, isPopoutOpen]);

  const handleGate = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const code = (new FormData(e.currentTarget)).get('code') as string;
    if (code.toUpperCase() === COMMUNITY_CODE) {
      localStorage.setItem('ppe_auth', 'true');
      setIsGated(false);
    } else {
      alert('Invalid Community Code');
    }
  };

  const handleSendMessage = async (text: string = inputValue) => {
    const messageToSend = text.trim();
    if (!messageToSend) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), sender: 'user', text: messageToSend, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');

    const response = await chatWithAI(messageToSend);
    const aiMsg: ChatMessage = { id: (Date.now() + 1).toString(), sender: 'ai', text: response, timestamp: new Date() };
    setMessages(prev => [...prev, aiMsg]);
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  if (isGated && activePage !== 'home') {
    return (
      <div className="min-h-screen bg-navy flex items-center justify-center p-6 text-center">
        <Card className="max-w-md w-full py-10">
          <div className="w-16 h-16 bg-gold rounded-full flex items-center justify-center text-navy font-bold text-3xl mx-auto mb-6">P</div>
          <Title>Residents Only</Title>
          <p className="mb-8 text-sm text-bodyText leading-relaxed">Please enter the community code provided in the monthly newsletter to access the full resident portal.</p>
          <form onSubmit={handleGate} className="space-y-4">
            <input 
              name="code"
              type="text" 
              placeholder="Enter Code (e.g. GOLF55)" 
              className="w-full px-4 py-3 rounded-xl border border-border focus:outline-none focus:ring-2 focus:ring-gold text-center font-mono tracking-widest text-lg"
            />
            <Button className="w-full py-4 text-lg">Enter Portal</Button>
            <button onClick={() => setIsGated(false)} className="text-xs text-slate-400 mt-4 block mx-auto underline">Go Back to Public Website</button>
          </form>
        </Card>
      </div>
    );
  }

  const renderContent = () => {
    switch (activePage) {
      case 'home':
        return (
          <div className="space-y-8 animate-fadeIn pb-12">
            <div className="relative rounded-3xl overflow-hidden h-48 md:h-64 mb-8 group">
              <img src="https://picsum.photos/1200/800?golf" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="Golf Course" />
              <div className="absolute inset-0 bg-gradient-to-t from-navy/80 via-navy/20 to-transparent flex flex-col justify-end p-6">
                <h2 className="text-3xl md:text-4xl text-white font-bold mb-1">Welcome Home</h2>
                <p className="text-gold font-medium uppercase tracking-widest text-xs">Polo Park East Golf & Country Club</p>
              </div>
            </div>

            <SectionHeader title="Quick Actions" />
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {[
                { label: 'Tee Times', icon: ICONS.Golf, color: 'bg-emerald-50 text-emerald-600', page: 'amenities' },
                { label: 'Resident Directory', icon: ICONS.User, color: 'bg-blue-50 text-blue-600', page: 'directory' },
                { label: 'Event RSVP', icon: ICONS.Calendar, color: 'bg-amber-50 text-amber-600', page: 'events' },
                { label: 'Concierge', icon: ICONS.Chat, color: 'bg-indigo-50 text-indigo-600', page: 'ai' }
              ].map((item, i) => (
                <Card key={i} onClick={() => setActivePage(item.page as PageType)} className="flex flex-col items-center justify-center py-6 hover:translate-y-[-2px]">
                  <div className={`p-4 rounded-full mb-3 ${item.color}`}><item.icon /></div>
                  <span className="text-xs font-bold text-navy uppercase tracking-tight">{item.label}</span>
                </Card>
              ))}
            </div>

            <SectionHeader title="Latest Announcements" subtitle="Stay updated with the community" />
            <div className="space-y-4">
              {MOCK_ANNOUNCEMENTS.map(item => (
                <Card key={item.id} className="relative overflow-hidden">
                  {item.isPinned && <div className="absolute top-0 left-0 w-1 h-full bg-gold" />}
                  <div className="flex justify-between items-start mb-2">
                    <GoldBadge>{item.category}</GoldBadge>
                    <span className="text-[10px] text-slate-400 font-medium">{item.date}</span>
                  </div>
                  <h3 className="text-lg font-bold text-navy mb-2">{item.title}</h3>
                  <p className="text-sm text-bodyText line-clamp-2">{item.content}</p>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'events':
        return (
          <div className="space-y-6">
            <SectionHeader title="Upcoming Events" subtitle="Find your next community gathering" />
            <div className="flex space-x-2 overflow-x-auto hide-scrollbar pb-2">
              {['All', 'Social', 'Sports', 'Meeting'].map(cat => (
                <button key={cat} className="px-4 py-2 rounded-full border border-border bg-white text-xs font-bold whitespace-nowrap hover:bg-gold hover:text-navy transition-colors">
                  {cat}
                </button>
              ))}
            </div>
            <div className="space-y-4">
              {MOCK_EVENTS.map(event => (
                <Card key={event.id} className="flex flex-col md:flex-row gap-6">
                  <div className="md:w-32 flex flex-col items-center justify-center bg-goldTint rounded-xl p-4 text-goldPressed">
                    <span className="text-sm font-bold uppercase">{event.date.split('-')[1]}</span>
                    <span className="text-3xl font-bold">{event.date.split('-')[2]}</span>
                    <span className="text-xs font-medium uppercase">{event.time}</span>
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between items-start mb-1">
                      <h3 className="text-xl font-bold text-navy">{event.title}</h3>
                      <GoldBadge>{event.category}</GoldBadge>
                    </div>
                    <p className="text-sm text-bodyText mb-4">{event.description}</p>
                    <div className="flex items-center space-x-4 text-xs font-medium text-slate-400 mb-4">
                      <div className="flex items-center"><ICONS.Location /> <span className="ml-1">{event.location}</span></div>
                      <div className="flex items-center"><ICONS.User /> <span className="ml-1">{event.rsvps}/{event.capacity} Attending</span></div>
                    </div>
                    <div className="flex space-x-2">
                      <Button className="flex-1">RSVP Yes</Button>
                      <Button variant="outline" className="flex-1">Maybe</Button>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'amenities':
        return (
          <div className="space-y-6">
            <SectionHeader title="Amenities & Facilities" subtitle="Available to all residents" />
            <div className="grid grid-cols-1 gap-6">
              {MOCK_AMENITIES.map(amenity => (
                <Card key={amenity.id} className="p-0 overflow-hidden">
                  <img src={amenity.image} className="w-full h-48 object-cover" />
                  <div className="p-6">
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xl font-bold text-navy">{amenity.name}</h3>
                      <div className="p-3 bg-goldTint rounded-full text-gold"><ICONS.Golf /></div>
                    </div>
                    <div className="grid grid-cols-2 gap-4 mb-4">
                      <div>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Hours</span>
                        <p className="text-sm text-navy font-semibold">{amenity.hours}</p>
                      </div>
                      <div>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Access</span>
                        <p className="text-sm text-navy font-semibold">Key Fob Required</p>
                      </div>
                    </div>
                    <div>
                      <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-2">Rules Highlights</span>
                      <ul className="space-y-1">
                        {amenity.rules.map((rule, idx) => (
                          <li key={idx} className="text-xs text-bodyText flex items-center">
                            <div className="w-1 h-1 rounded-full bg-gold mr-2" /> {rule}
                          </li>
                        ))}
                      </ul>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'directory':
        return (
          <div className="space-y-6">
            <SectionHeader title="Resident Directory" subtitle="Connect with your neighbors" />
            <div className="relative">
              <input 
                type="text" 
                placeholder="Search residents by name or interest..." 
                className="w-full pl-12 pr-4 py-3 rounded-xl border border-border bg-white focus:outline-none focus:ring-2 focus:ring-gold"
              />
              <div className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"><ICONS.Search /></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {MOCK_RESIDENTS.map(res => (
                <Card key={res.id} className="flex items-center space-x-4">
                  <div className="relative">
                    <img src={res.avatar} className="w-16 h-16 rounded-2xl object-cover" />
                    <div className="absolute -bottom-1 -right-1 bg-gold text-navy text-[8px] font-black px-1.5 py-0.5 rounded-md shadow-sm">
                      {res.points} PTS
                    </div>
                  </div>
                  <div className="flex-1">
                    <h3 className="text-lg font-bold text-navy leading-none mb-1">{res.name}</h3>
                    <p className="text-xs text-slate-400 mb-2">{res.interests.join(' • ')}</p>
                    <div className="flex space-x-2">
                      <Button variant="outline" className="px-3 py-1 text-[10px]">Message</Button>
                      <Button variant="outline" className="px-3 py-1 text-[10px]">View House</Button>
                    </div>
                  </div>
                  <div className={`w-2 h-2 rounded-full ${res.messagingEnabled ? 'bg-green-400' : 'bg-slate-200'}`} />
                </Card>
              ))}
            </div>

            <SectionHeader title="Preferences" subtitle="Notification controls" />
            <Card className="space-y-4">
              {(['announcements', 'events', 'messages'] as const).map((key) => (
                <div key={key} className="flex items-center justify-between py-2 border-b border-border last:border-0">
                  <span className="text-sm font-bold text-navy capitalize">{key} Notifications</span>
                  <button 
                    onClick={() => setNotifSettings(prev => ({ ...prev, [key]: !prev[key] }))}
                    className={`w-12 h-6 rounded-full relative transition-colors ${notifSettings[key] ? 'bg-gold' : 'bg-slate-200'}`}
                  >
                    <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${notifSettings[key] ? 'left-7' : 'left-1'}`} />
                  </button>
                </div>
              ))}
            </Card>
          </div>
        );

      case 'forum':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <SectionHeader title="Community Forum" />
              <Button onClick={() => alert("Write mode enabled. Posting gated by community code.")}>New Post</Button>
             </div>
             <div className="space-y-4">
                {MOCK_FORUM.map(topic => (
                  <Card key={topic.id} className="hover:border-gold">
                    <div className="flex justify-between items-start mb-2">
                      <GoldBadge>{topic.category}</GoldBadge>
                      <span className="text-[10px] text-slate-400">{topic.lastActivity}</span>
                    </div>
                    <h3 className="text-lg font-bold text-navy mb-1">{topic.title}</h3>
                    <div className="flex justify-between items-center text-xs text-bodyText">
                      <span>Started by {topic.author}</span>
                      <div className="flex items-center space-x-1"><ICONS.Chat /><span className="text-[10px] font-bold">{topic.replies} REPLIES</span></div>
                    </div>
                  </Card>
                ))}
             </div>
          </div>
        );

      case 'ai':
        return (
          <div className="flex flex-col h-[calc(100vh-200px)] animate-fadeIn">
            <SectionHeader title="Concierge AI" subtitle="Ask about rules, FAQs, or golf" />
            <div id="chat-scroll" className="flex-1 overflow-y-auto space-y-4 pb-4 pr-2 hide-scrollbar">
              {messages.map(msg => (
                <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm ${
                    msg.sender === 'user' ? 'bg-gold text-navy rounded-tr-none' : 'bg-white border border-border text-navy rounded-tl-none'
                  }`}>
                    {msg.text}
                  </div>
                </div>
              ))}
            </div>

            <div className="flex space-x-2 overflow-x-auto hide-scrollbar py-3">
              {["What are pool hours?", "Guest policy?", "Pet rules?", "Golf dress code?"].map(hint => (
                <button 
                  key={hint}
                  onClick={() => handleSendMessage(hint)}
                  className="px-3 py-1.5 bg-white border border-border rounded-full text-[10px] font-bold text-navy whitespace-nowrap hover:border-gold transition-colors"
                >
                  {hint}
                </button>
              ))}
            </div>

            <div className="p-2 bg-white border border-border rounded-2xl flex items-center space-x-2 shadow-lg">
              <input 
                type="text" 
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Ask about hours, rules, or events..." 
                className="flex-1 bg-transparent border-none focus:outline-none px-2 py-2 text-sm"
              />
              <button 
                onClick={() => handleSendMessage()}
                className="p-2 bg-gold text-navy rounded-xl hover:bg-goldPressed transition-all"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
            </div>
            <p className="text-[10px] text-slate-400 mt-2 text-center uppercase tracking-widest font-bold">Grounded in Community Rules & FAQs</p>
          </div>
        );

      case 'notifications':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <SectionHeader title="Notifications" subtitle="Stay in the loop" />
              <button onClick={markAllRead} className="text-xs font-bold text-gold uppercase tracking-widest">Mark all as read</button>
            </div>
            <div className="space-y-3">
              {notifications.length === 0 ? (
                <div className="py-20 text-center text-slate-400">
                  <ICONS.Bell />
                  <p className="mt-2 text-sm">No new notifications</p>
                </div>
              ) : (
                notifications.map(notif => (
                  <Card key={notif.id} className={`flex items-start space-x-4 ${!notif.read ? 'border-l-4 border-l-gold' : ''}`}>
                    <div className={`p-3 rounded-xl ${notif.type === 'event' ? 'bg-amber-50 text-amber-600' : 'bg-blue-50 text-blue-600'}`}>
                      {notif.type === 'event' ? <ICONS.Calendar /> : <ICONS.Announcement />}
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between items-center mb-1">
                        <h4 className="font-bold text-navy">{notif.title}</h4>
                        <span className="text-[10px] text-slate-400 uppercase font-bold">Just Now</span>
                      </div>
                      <p className="text-xs text-bodyText">{notif.message}</p>
                    </div>
                  </Card>
                ))
              )}
            </div>
          </div>
        );

      case 'admin':
        if (!adminAuth) {
          return (
            <div className="max-w-md mx-auto py-20 text-center">
              <Title>Admin Login</Title>
              <form onSubmit={(e) => {
                e.preventDefault();
                const code = (new FormData(e.currentTarget)).get('pass') as string;
                if (code === ADMIN_PASSCODE) setAdminAuth(true);
                else alert('Wrong passcode');
              }}>
                <input name="pass" type="password" placeholder="Passcode" className="w-full p-4 rounded-xl border border-border mb-4 text-center" />
                <Button className="w-full">Unlock Dashboard</Button>
              </form>
            </div>
          );
        }
        return (
          <div className="space-y-6">
             <SectionHeader title="Admin Dashboard" subtitle="Manage community knowledge" />
             <div className="grid grid-cols-2 gap-4">
                {[
                  { label: 'Broadcast Notif', action: () => alert("Notification sent to all residents") },
                  { label: 'Edit Knowledge Base', action: () => alert("Knowledge base updated for AI") },
                  { label: 'Manage Events', action: () => setActivePage('events') },
                  { label: 'Reports', action: () => alert("No reports active") }
                ].map(item => (
                  <Card key={item.label} className="py-8 flex flex-col items-center text-center cursor-pointer hover:bg-goldTint" onClick={item.action}>
                    <span className="font-bold text-navy text-sm">{item.label}</span>
                    <button className="text-[10px] text-gold font-bold mt-2 uppercase">Open →</button>
                  </Card>
                ))}
             </div>
             <Button variant="outline" className="w-full" onClick={() => setAdminAuth(false)}>Logout</Button>
          </div>
        );

      default:
        return <div>Page coming soon...</div>;
    }
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <Layout activePage={activePage} setActivePage={setActivePage} isGated={isGated} unreadCount={unreadCount}>
      {renderContent()}

      {/* Persistent Floating AI Concierge Bubble - Hidden on AI section */}
      {activePage !== 'ai' && !isGated && (
        <div className="fixed bottom-24 right-4 md:bottom-28 md:right-8 z-[60] flex flex-col items-end">
          {/* Pop-out Chat Interface */}
          {isPopoutOpen && (
            <div className="mb-4 w-72 h-96 bg-white rounded-3xl shadow-2xl border border-border overflow-hidden flex flex-col animate-fadeIn">
              {/* Pop-out Header - STRICT NAVY BLUE (#0F2233) */}
              <div className="bg-navy p-4 flex justify-between items-center shadow-md">
                <div className="flex items-center space-x-2">
                  <div className="w-6 h-6 bg-gold rounded-full flex items-center justify-center text-navy font-bold text-[10px]">P</div>
                  <span className="text-white text-xs font-bold uppercase tracking-widest">Concierge Chat</span>
                </div>
                <button onClick={() => setIsPopoutOpen(false)} className="text-white/60 hover:text-white transition-colors">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              {/* Pop-out Body - Last 10 messages */}
              <div ref={popoutScrollRef} className="flex-1 overflow-y-auto p-4 space-y-3 hide-scrollbar bg-bgMain">
                {messages.slice(-10).map(msg => (
                  <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[90%] px-3 py-2 rounded-2xl text-[11px] shadow-sm ${
                      msg.sender === 'user' ? 'bg-gold text-navy rounded-tr-none' : 'bg-white border border-border text-navy rounded-tl-none'
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                ))}
              </div>

              {/* Pop-out Footer */}
              <div className="p-2 bg-white border-t border-border flex items-center space-x-2">
                <input 
                  type="text" 
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                  placeholder="Ask a question..." 
                  className="flex-1 bg-transparent text-xs px-2 py-1.5 focus:outline-none"
                />
                <button onClick={() => handleSendMessage()} className="p-1.5 bg-gold text-navy rounded-lg hover:bg-goldPressed transition-colors">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 12h14M12 5l7 7-7 7" /></svg>
                </button>
              </div>
            </div>
          )}

          {/* Main Bubble Button */}
          <button 
            onClick={() => setIsPopoutOpen(!isPopoutOpen)}
            className="w-14 h-14 bg-gold text-navy rounded-full shadow-2xl flex items-center justify-center hover:scale-105 active:scale-95 transition-all group relative border-4 border-white"
          >
            {isPopoutOpen ? (
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
            ) : (
              <div className="relative">
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/></svg>
                {/* Notification Indicator */}
                <div className="absolute -top-1 -right-1 w-3.5 h-3.5 bg-red-500 border-2 border-gold rounded-full animate-pulse shadow-sm" />
              </div>
            )}
          </button>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React from 'react';
import { Announcement, Event, Amenity, Resident, ForumTopic, FAQ, Rule } from './types';

export const COMMUNITY_CODE = "poloparkeast";
export const ADMIN_PASSCODE = "PPE2024";

export const ICONS = {
  Golf: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 11V9a2 2 0 00-2-2m2 4v4a2 2 0 104 0v-1m-4-3H9m2 0h4m6 1a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>,
