                    <div className="flex items-center space-x-4 text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">
                      <div className="flex items-center"><ICONS.Location /> <span className="ml-1.5">{event.location}</span></div>
                      <div className="flex items-center"><ICONS.User /> <span className="ml-1.5">{event.rsvps}/{event.capacity} Attending</span></div>
                    </div>
                    <div className="flex space-x-3">
                      <Button className="flex-1 py-3">RSVP Yes</Button>
                      <Button variant="outline" className="flex-1 py-3 border-2">Maybe</Button>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'amenities':
        return (
          <div className="space-y-6">
            <SectionHeader title="Amenities & Facilities" subtitle="Available to all residents" />
            <div className="grid grid-cols-1 gap-6">
              {MOCK_AMENITIES.map(amenity => (
                <Card key={amenity.id} className="p-0 overflow-hidden hover:border-gold transition-all duration-300">
                  <img src={amenity.image} className="w-full h-56 object-cover" />
                  <div className="p-6">
                    <div className="flex items-center justify-between mb-5">
                      <h3 className="text-2xl font-bold text-navy">{amenity.name}</h3>
                      <div className="p-4 bg-goldTint rounded-full text-gold border border-gold/10"><ICONS.Golf /></div>
                    </div>
                    <div className="grid grid-cols-2 gap-4 mb-6">
                      <div className="p-3 bg-bgMain rounded-xl border border-border/50">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Operating Hours</span>
                        <p className="text-sm text-navy font-bold">{amenity.hours}</p>
