                      </div>
                    </div>
                    <div className="bg-goldTint/10 p-4 rounded-xl border border-gold/10">
                      <span className="text-[10px] font-black text-goldPressed uppercase tracking-widest block mb-3">Facility Rules & Policy</span>
                      <ul className="grid grid-cols-1 md:grid-cols-2 gap-2">
                        {amenity.rules.map((rule, idx) => (
                          <li key={idx} className="text-xs text-bodyText flex items-center">
                            <div className="w-1.5 h-1.5 rounded-full bg-gold mr-3 flex-shrink-0" /> {rule}
