                        ))}
                      </ul>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'directory':
        return (
          <div className="space-y-6">
            <SectionHeader title="Resident Directory" subtitle="Connect with your neighbors" />
            <div className="relative">
              <input 
                type="text" 
                placeholder="Search residents by name or interest..." 
                className="w-full pl-12 pr-4 py-4 rounded-xl border-2 border-border focus:border-gold focus:outline-none bg-white shadow-sm transition-all"
