                <Card key={res.id} className="flex items-center space-x-5 hover:border-gold transition-all duration-300">
                  <div className="relative">
                    <img src={res.avatar} className="w-20 h-20 rounded-2xl object-cover shadow-md border-2 border-white" />
                    <div className="absolute -bottom-2 -right-2 bg-gold text-navy text-[9px] font-black px-2 py-1 rounded-lg shadow-md border-2 border-white">
                      {res.points} PTS
