                      <Button variant="outline" className="px-4 py-1.5 text-[10px] h-9 border-2 uppercase tracking-widest">Message</Button>
                      <Button variant="outline" className="px-4 py-1.5 text-[10px] h-9 border-2 uppercase tracking-widest">Profile</Button>
                    </div>
                  </div>
                  <div className={`w-3 h-3 rounded-full ${res.messagingEnabled ? 'bg-green-400 shadow-[0_0_10px_rgba(74,222,128,0.6)]' : 'bg-slate-200'}`} />
                </Card>
              ))}
            </div>

            <SectionHeader title="Preferences" subtitle="Notification controls" />
            <Card className="space-y-4 border-2 border-gold/10">
              {(['announcements', 'events', 'messages'] as const).map((key) => (
                <div key={key} className="flex items-center justify-between py-2 border-b border-border/50 last:border-0">
                  <span className="text-sm font-black text-navy uppercase tracking-wider">{key} Notifications</span>
                  <button 
                    onClick={() => setNotifSettings(prev => ({ ...prev, [key]: !prev[key] }))}
                    className={`w-14 h-7 rounded-full relative transition-all duration-300 ${notifSettings[key] ? 'bg-gold shadow-lg shadow-gold/20' : 'bg-slate-200'}`}
                  >
                    <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-all shadow-md ${notifSettings[key] ? 'left-8' : 'left-1'}`} />
                  </button>
                </div>
              ))}
            </Card>
          </div>
        );

      case 'forum':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <SectionHeader title="Community Forum" />
              <Button onClick={() => alert("Write mode enabled. Posting gated by community code.")} className="px-8">Create Thread</Button>
             </div>
             <div className="space-y-4">
                {MOCK_FORUM.map(topic => (
                  <Card key={topic.id} className="hover:border-gold border-2 border-border/50 transition-all duration-300">
                    <div className="flex justify-between items-start mb-3">
                      <GoldBadge>{topic.category}</GoldBadge>
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{topic.lastActivity}</span>
                    </div>
                    <h3 className="text-xl font-bold text-navy mb-2 hover:text-gold transition-colors">{topic.title}</h3>
                    <div className="flex justify-between items-center text-xs text-bodyText">
                      <span className="font-medium text-slate-500 italic">Discussion by {topic.author}</span>
                      <div className="flex items-center space-x-2 text-gold">
                        <ICONS.Chat />
                        <span className="text-[10px] font-black text-goldPressed uppercase tracking-widest">{topic.replies} REPLIES</span>
                      </div>
                    </div>
                  </Card>
                ))}
             </div>
          </div>
        );

      case 'ai':
        return (
          <div className="flex flex-col h-[calc(100vh-200px)] animate-fadeIn">
            <SectionHeader title="Concierge AI" subtitle="Ask about community rules, events, or golf" />
            <div id="chat-scroll" className="flex-1 overflow-y-auto space-y-4 pb-4 pr-2 hide-scrollbar">
              {messages.map(msg => (
                <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] px-5 py-3 rounded-2xl text-sm shadow-md leading-relaxed ${
                    msg.sender === 'user' ? 'bg-gold text-navy rounded-tr-none font-medium' : 'bg-white border-2 border-border text-navy rounded-tl-none'
                  }`}>
