                  </div>
                </div>
              ))}
            </div>

            <div className="flex space-x-2 overflow-x-auto hide-scrollbar py-4">
              {["What are pool hours?", "Guest policy?", "Pet rules?", "Golf dress code?"].map(hint => (
                <button 
                  key={hint}
                  onClick={() => handleSendMessage(hint)}
                  className="px-4 py-2 bg-white border-2 border-gold/30 rounded-full text-[10px] font-black text-navy uppercase tracking-widest whitespace-nowrap hover:border-gold hover:bg-goldTint/20 transition-all"
                >
                  {hint}
                </button>
              ))}
            </div>

            <div className="p-2.5 bg-white border-2 border-gold/20 rounded-2xl flex items-center space-x-3 shadow-2xl">
              <input 
                type="text" 
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Ask about hours, rules, or events..." 
                className="flex-1 bg-transparent border-none focus:outline-none px-3 py-3 text-sm font-medium"
              />
              <button 
                onClick={() => handleSendMessage()}
                className="p-3 bg-gold text-navy rounded-xl hover:bg-goldPressed transition-all shadow-lg active:scale-90"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.3" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
            </div>
            <p className="text-[10px] text-slate-400 mt-3 text-center uppercase tracking-widest font-black">Grounded in Community Rules & Official FAQs</p>
          </div>
        );

      case 'notifications':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <SectionHeader title="Communications" subtitle="Important updates for residents" />
              <button onClick={markAllRead} className="text-[10px] font-black text-gold uppercase tracking-widest hover:text-goldPressed transition-colors">Clear All Unread</button>
            </div>
            <div className="space-y-3">
              {notifications.length === 0 ? (
                <div className="py-24 text-center text-slate-400">
                  <div className="mx-auto mb-6 opacity-20"><ICONS.Bell /></div>
                  <p className="mt-2 text-sm font-medium uppercase tracking-widest">No Active Notifications</p>
                </div>
              ) : (
                notifications.map(notif => (
                  <Card key={notif.id} className={`flex items-start space-x-5 transition-all duration-300 ${!notif.read ? 'border-l-4 border-l-gold bg-goldTint/10' : 'border-2 border-border/40'}`}>
                    <div className={`p-4 rounded-2xl shadow-sm border border-white ${notif.type === 'event' ? 'bg-amber-100 text-amber-600' : 'bg-blue-100 text-blue-600'}`}>
                      {notif.type === 'event' ? <ICONS.Calendar /> : <ICONS.Announcement />}
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between items-center mb-1.5">
                        <h4 className="font-bold text-navy text-lg">{notif.title}</h4>
                        <span className="text-[10px] text-slate-400 uppercase font-black tracking-widest">Now</span>
                      </div>
                      <p className="text-sm text-bodyText leading-relaxed font-medium">{notif.message}</p>
                    </div>
                  </Card>
                ))
              )}
            </div>
          </div>
        );

      case 'admin':
        if (!adminAuth) {
          return (
            <div className="max-w-md mx-auto py-20 text-center">
              <Title>Administrative Portal</Title>
              <Card className="shadow-2xl py-12 border-2 border-gold/30">
                <form onSubmit={(e) => {
                  e.preventDefault();
                  const code = (new FormData(e.currentTarget)).get('pass') as string;
                  if (code === ADMIN_PASSCODE) setAdminAuth(true);
                  else alert('Wrong passcode');
                }}>
                  <input name="pass" type="password" placeholder="Admin Passcode" className="w-full p-4 rounded-xl border-2 border-border mb-6 text-center focus:border-navy focus:ring-0 outline-none text-xl tracking-widest" />
                  <Button className="w-full h-16 text-lg tracking-widest">Unlock Portal</Button>
                </form>
              </Card>
            </div>
          );
        }
        return (
          <div className="space-y-6">
             <SectionHeader title="Management Suite" subtitle="Oversee community knowledge & records" />
             <div className="grid grid-cols-2 gap-5">
                {[
                  { label: 'Push Notification', icon: ICONS.Bell, action: () => alert("Notification sent to all residents") },
                  { label: 'Knowledge Base', icon: ICONS.Chat, action: () => alert("Knowledge base updated for AI") },
                  { label: 'Event Ledger', icon: ICONS.Calendar, action: () => setActivePage('events') },
                  { label: 'Moderation', icon: ICONS.Announcement, action: () => alert("No reports active") }
                ].map(item => (
                  <Card key={item.label} className="py-10 flex flex-col items-center text-center cursor-pointer border-2 border-gold/20 hover:border-gold hover:bg-goldTint/10 transition-all duration-300" onClick={item.action}>
                    <div className="text-gold mb-4 scale-150"><item.icon /></div>
                    <span className="font-black text-navy text-xs uppercase tracking-widest">{item.label}</span>
                    <button className="text-[10px] text-gold font-black mt-4 uppercase tracking-[0.2em]">Open Module →</button>
                  </Card>
                ))}
             </div>
             <Button variant="outline" className="w-full mt-12 h-14 border-2 tracking-widest" onClick={() => setAdminAuth(false)}>Terminate Admin Session</Button>
          </div>
        );

      default:
        return <div>Page coming soon...</div>;
    }
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <Layout activePage={activePage} setActivePage={setActivePage} isGated={isGated} unreadCount={unreadCount}>
      {renderContent()}

      {/* Persistent Floating AI Concierge Bubble - Hidden on AI section */}
      {activePage !== 'ai' && !isGated && (
        <div className="fixed bottom-24 right-4 md:bottom-28 md:right-8 z-[60] flex flex-col items-end">
          {/* Pop-out Chat Interface */}
          {isPopoutOpen && (
            <div className="mb-5 w-80 h-[450px] bg-white rounded-[32px] shadow-[0_25px_60px_rgba(0,0,0,0.2)] border-2 border-gold/20 overflow-hidden flex flex-col animate-fadeIn">
              {/* Pop-out Header - STRICT NAVY BLUE (#0F2233) */}
              <div className="bg-navy p-5 flex justify-between items-center shadow-lg">
                <div className="flex items-center space-x-3">
                  <div className="w-8 h-8 bg-gold rounded-full flex items-center justify-center text-navy font-black text-xs">P</div>
                  <div>
                    <span className="text-white text-[11px] font-black uppercase tracking-widest block">PPE Concierge</span>
                    <span className="text-gold text-[9px] font-bold uppercase tracking-widest">AI Agent Online</span>
                  </div>
                </div>
                <button onClick={() => setIsPopoutOpen(false)} className="text-white/40 hover:text-white transition-colors p-2 bg-white/5 rounded-full">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              {/* Pop-out Body - Last 10 messages */}
              <div ref={popoutScrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 hide-scrollbar bg-bgMain">
                {messages.slice(-10).map(msg => (
                  <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-[12px] shadow-sm leading-relaxed ${
                      msg.sender === 'user' ? 'bg-gold text-navy rounded-tr-none font-bold' : 'bg-white border-2 border-border text-navy rounded-tl-none font-medium'
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                ))}
              </div>

              {/* Pop-out Footer */}
              <div className="p-3 bg-white border-t-2 border-border/30 flex items-center space-x-2">
                <input 
                  type="text" 
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                  placeholder="Type your message..." 
                  className="flex-1 bg-transparent text-sm px-3 py-2.5 focus:outline-none font-medium"
                />
                <button onClick={() => handleSendMessage()} className="p-3 bg-gold text-navy rounded-xl hover:bg-goldPressed transition-all shadow-md active:scale-90">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 12h14M12 5l7 7-7 7" /></svg>
                </button>
              </div>
            </div>
          )}

          {/* Main Bubble Button */}
          <button 
            onClick={() => setIsPopoutOpen(!isPopoutOpen)}
            className="w-16 h-16 bg-gold text-navy rounded-full shadow-[0_15px_40px_rgba(242,178,51,0.4)] flex items-center justify-center hover:scale-110 active:scale-95 transition-all group relative border-4 border-white"
          >
            {isPopoutOpen ? (
               <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7" /></svg>
            ) : (
              <div className="relative">
                <svg className="w-7 h-7" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/></svg>
                {/* Notification Indicator */}
                <div className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-red-500 border-4 border-gold rounded-full animate-pulse shadow-md" />
              </div>
            )}
          </button>
        </div>
      )}
    </Layout>
  );
};

export default App;

