  // Notification State
  const [notifications, setNotifications] = useState<AppNotification[]>([
    { id: '1', title: 'New Event!', message: 'Pickleball Mixer has been added for next Saturday.', type: 'event', timestamp: new Date(), read: false },
    { id: '2', title: 'Maintenance Alert', message: 'Pool closing reminder for Oct 10th.', type: 'announcement', timestamp: new Date(), read: false }
  ]);
  const [notifSettings, setNotifSettings] = useState<NotificationSettings>({
    announcements: true,
    events: true,
    messages: false
  });

  // Auto-scroll for chat
  useEffect(() => {
    if (activePage === 'ai') {
      const el = document.getElementById('chat-scroll');
      if (el) el.scrollTop = el.scrollHeight;
    }
    if (isPopoutOpen && popoutScrollRef.current) {
      popoutScrollRef.current.scrollTop = popoutScrollRef.current.scrollHeight;
    }
  }, [messages, activePage, isPopoutOpen]);

  const handleGate = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const code = (new FormData(e.currentTarget)).get('code') as string;
    if (code.toLowerCase() === COMMUNITY_CODE.toLowerCase()) {
      localStorage.setItem('ppe_auth', 'true');
      setIsGated(false);
    } else {
      alert('Invalid Community Code');
    }
  };

  const handleSendMessage = async (text: string = inputValue) => {
    const messageToSend = text.trim();
    if (!messageToSend) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), sender: 'user', text: messageToSend, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');

    const response = await chatWithAI(messageToSend);
    const aiMsg: ChatMessage = { id: (Date.now() + 1).toString(), sender: 'ai', text: response, timestamp: new Date() };
    setMessages(prev => [...prev, aiMsg]);
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  if (isGated && activePage !== 'home') {
    return (
      <div className="min-h-screen bg-navy flex items-center justify-center p-6 text-center">
        <Card className="max-w-md w-full py-10 shadow-2xl border border-black">
          <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mx-auto mb-8 border border-black overflow-hidden shadow-md">
            <img src="/brand/logo.png" alt="Polo Park East Logo" className="w-full h-full object-contain" />
          </div>
          <Title>Residents Only</Title>
          <p className="mb-8 text-sm text-bodyText leading-relaxed px-4">Please enter the resident code to access the Polo Park East community portal.</p>
          <form onSubmit={handleGate} className="space-y-4 px-6">
            <input 
              name="code"
              type="text" 
              placeholder="Enter Resident Code" 
              className="w-full px-4 py-3 rounded-xl border border-black focus:outline-none focus:ring-2 focus:ring-gold text-center tracking-wide text-lg font-bold"
            />
            <Button className="w-full py-4 text-lg">Enter Portal</Button>
            <button onClick={() => setIsGated(false)} className="text-xs text-slate-400 mt-4 block mx-auto underline hover:text-gold transition-colors">Go Back to Public Website</button>
          </form>
        </Card>
      </div>
    );
  }

  const renderContent = () => {
    switch (activePage) {
      case 'home':
        return (
          <div className="space-y-8 animate-fadeIn pb-12">
            <div className="relative rounded-3xl overflow-hidden h-48 md:h-64 mb-8 group shadow-lg border border-black">
              <img src="/brand/entrance.jpg" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="Polo Park East Entrance" />
              <div className="absolute inset-0 bg-gradient-to-t from-navy/90 via-navy/30 to-transparent flex flex-col justify-end p-6">
                <h2 className="text-3xl md:text-4xl text-white font-bold mb-1 shadow-sm">Welcome Home</h2>
                <p className="text-gold font-black uppercase tracking-widest text-xs shadow-sm">Polo Park East Golf & Country Club</p>
              </div>
            </div>

            <SectionHeader title="Quick Actions" />
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {[
                { label: 'Tee Times', icon: ICONS.Golf, page: 'amenities' },
                { label: 'Neighbors', icon: ICONS.User, page: 'directory' },
                { label: 'Event RSVP', icon: ICONS.Calendar, page: 'events' },
                { label: 'Concierge', icon: ICONS.Chat, page: 'ai' }
              ].map((item, i) => (
                <Card 
                  key={i} 
                  onClick={() => setActivePage(item.page as PageType)} 
                  className="flex flex-col items-center justify-center py-8 bg-gold border border-black hover:translate-y-[-2px] transition-all group active:scale-95"
                >
                  <div className="text-navy mb-3 scale-125 group-hover:scale-150 transition-transform duration-300">
                    <item.icon />
                  </div>
                  <span className="text-[10px] font-black text-navy uppercase tracking-widest text-center px-1">{item.label}</span>
                </Card>
              ))}
            </div>

            <SectionHeader title="Latest Announcements" subtitle="Stay updated with the community" />
            <div className="space-y-4">
              {MOCK_ANNOUNCEMENTS.map(item => (
                <Card key={item.id} className="relative overflow-hidden group hover:border-black transition-all">
                  {item.isPinned && <div className="absolute top-0 left-0 w-1.5 h-full bg-navy" />}
                  <div className="flex justify-between items-start mb-2">
                    <GoldBadge>{item.category}</GoldBadge>
                    <span className="text-[10px] text-slate-400 font-medium">{item.date}</span>
                  </div>
                  <h3 className="text-lg font-bold text-navy mb-2 group-hover:text-gold transition-colors">{item.title}</h3>
                  <p className="text-sm text-bodyText line-clamp-2">{item.content}</p>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'events':
        return (
          <div className="space-y-6">
            <SectionHeader title="Upcoming Events" subtitle="Find your next community gathering" />
            <div className="flex space-x-2 overflow-x-auto hide-scrollbar pb-2">
              {['All', 'Social', 'Sports', 'Meeting'].map(cat => (
                <button key={cat} className="px-4 py-2 rounded-full border border-black bg-white text-xs font-black uppercase tracking-widest text-navy hover:bg-gold transition-colors shadow-sm">
                  {cat}
                </button>
              ))}
            </div>
            <div className="space-y-4">
              {MOCK_EVENTS.map(event => (
                <Card key={event.id} className="flex flex-col md:flex-row gap-6 hover:border-black transition-all group">
                  <div className="md:w-32 flex flex-col items-center justify-center bg-gold rounded-xl p-4 text-navy border border-black shadow-sm group-hover:scale-105 transition-transform">
                    <span className="text-sm font-bold uppercase">{event.date.split('-')[1]}</span>
                    <span className="text-3xl font-black">{event.date.split('-')[2]}</span>
                    <span className="text-[10px] font-bold uppercase mt-1">{event.time}</span>
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between items-start mb-1">
                      <h3 className="text-xl font-bold text-navy">{event.title}</h3>
                      <GoldBadge>{event.category}</GoldBadge>
                    </div>
                    <p className="text-sm text-bodyText mb-4">{event.description}</p>
                    <div className="flex items-center space-x-4 text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">
                      <div className="flex items-center"><ICONS.Location /> <span className="ml-1.5">{event.location}</span></div>
                      <div className="flex items-center"><ICONS.User /> <span className="ml-1.5">{event.rsvps}/{event.capacity} Attending</span></div>
                    </div>
                    <div className="flex space-x-2">
                      <Button className="flex-1">RSVP Yes</Button>
                      <Button variant="outline" className="flex-1">Maybe</Button>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'amenities':
        return (
          <div className="space-y-6">
            <SectionHeader title="Amenities & Facilities" subtitle="Available to all residents" />
            <div className="grid grid-cols-1 gap-6">
              {MOCK_AMENITIES.map(amenity => (
                <Card key={amenity.id} className="p-0 overflow-hidden hover:border-black transition-all">
                  <img src={amenity.image} className="w-full h-48 object-cover border-b border-black" />
                  <div className="p-6">
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xl font-bold text-navy">{amenity.name}</h3>
                      <div className="p-3 bg-gold rounded-full text-navy border border-black shadow-sm"><ICONS.Golf /></div>
                    </div>
                    <div className="grid grid-cols-2 gap-4 mb-4">
                      <div className="p-3 bg-bgMain rounded-xl border border-black">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Hours</span>
                        <p className="text-sm text-navy font-bold">{amenity.hours}</p>
                      </div>
                      <div className="p-3 bg-bgMain rounded-xl border border-black">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Access</span>
                        <p className="text-sm text-navy font-bold">Resident Key Fob</p>
                      </div>
                    </div>
                    <div className="bg-goldTint p-4 rounded-xl border border-black">
                       <span className="text-[10px] font-black text-navy uppercase tracking-widest block mb-3 text-goldPressed">Facility Rules</span>
                        <ul className="grid grid-cols-1 md:grid-cols-2 gap-2">
                          {amenity.rules.map((rule, idx) => (
                            <li key={idx} className="text-xs text-bodyText flex items-center">
                              <div className="w-1.5 h-1.5 rounded-full bg-navy mr-3 flex-shrink-0" /> {rule}
                            </li>
                          ))}
                        </ul>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'directory':
        return (
          <div className="space-y-6">
            <SectionHeader title="Resident Directory" subtitle="Connect with your neighbors" />
            <div className="relative">
              <input 
                type="text" 
                placeholder="Search residents by name or interest..." 
                className="w-full pl-12 pr-4 py-3 rounded-xl border border-black bg-white focus:outline-none focus:ring-1 focus:ring-gold shadow-sm font-medium"
              />
              <div className="absolute left-4 top-1/2 -translate-y-1/2 text-navy"><ICONS.Search /></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {MOCK_RESIDENTS.map(res => (
                <Card key={res.id} className="flex items-center space-x-4 hover:border-black transition-all">
                  <div className="relative">
                    <img src={res.avatar} className="w-16 h-16 rounded-2xl object-cover shadow-sm border border-black" />
                    <div className="absolute -bottom-1 -right-1 bg-gold text-navy text-[8px] font-black px-1.5 py-0.5 rounded-md shadow-md border border-black">
                      {res.points} PTS
                    </div>
                  </div>
                  <div className="flex-1">
                    <h3 className="text-lg font-bold text-navy leading-none mb-1">{res.name}</h3>
                    <p className="text-xs text-slate-400 font-medium mb-2">{res.interests.join(' • ')}</p>
                    <div className="flex space-x-2">
                      <Button variant="outline" className="px-3 py-1 text-[10px] h-8">Message</Button>
                      <Button variant="outline" className="px-3 py-1 text-[10px] h-8">Profile</Button>
                    </div>
                  </div>
                  <div className={`w-2.5 h-2.5 rounded-full border border-black ${res.messagingEnabled ? 'bg-green-400' : 'bg-slate-200'}`} />
                </Card>
              ))}
            </div>

            <SectionHeader title="Preferences" subtitle="Notification controls" />
            <Card className="space-y-4 border border-black shadow-inner bg-bgMain/50">
              {(['announcements', 'events', 'messages'] as const).map((key) => (
                <div key={key} className="flex items-center justify-between py-2 border-b border-black last:border-0">
                  <span className="text-sm font-black text-navy uppercase tracking-widest">{key} Notifications</span>
                  <button 
                    onClick={() => setNotifSettings(prev => ({ ...prev, [key]: !prev[key] }))}
                    className={`w-12 h-6 rounded-full relative transition-colors border border-black ${notifSettings[key] ? 'bg-gold' : 'bg-slate-200'}`}
                  >
                    <div className={`absolute top-0.5 w-4 h-4 bg-white rounded-full transition-all shadow-sm border border-black ${notifSettings[key] ? 'left-[26px]' : 'left-0.5'}`} />
                  </button>
                </div>
              ))}
            </Card>
          </div>
        );

      case 'forum':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <SectionHeader title="Community Forum" />
              <Button onClick={() => alert("Write mode enabled. Posting gated by community code.")}>New Post</Button>
             </div>
             <div className="space-y-4">
                {MOCK_FORUM.map(topic => (
                  <Card key={topic.id} className="hover:border-black transition-all border border-black group">
                    <div className="flex justify-between items-start mb-2">
                      <GoldBadge>{topic.category}</GoldBadge>
                      <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{topic.lastActivity}</span>
                    </div>
                    <h3 className="text-lg font-bold text-navy mb-1 group-hover:text-goldPressed transition-colors">{topic.title}</h3>
                    <div className="flex justify-between items-center text-xs text-bodyText">
                      <span className="font-medium">Started by {topic.author}</span>
                      <div className="flex items-center space-x-1.5"><ICONS.Chat /><span className="text-[10px] font-black uppercase text-navy tracking-widest">{topic.replies} REPLIES</span></div>
                    </div>
                  </Card>
                ))}
             </div>
          </div>
        );

      case 'ai':
        return (
          <div className="flex flex-col h-[calc(100vh-200px)] animate-fadeIn">
            <SectionHeader title="Concierge AI" subtitle="Ask about community life" />
            <div id="chat-scroll" className="flex-1 overflow-y-auto space-y-4 pb-4 pr-2 hide-scrollbar">
              {messages.map(msg => (
                <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm shadow-sm border border-black ${
                    msg.sender === 'user' ? 'bg-gold text-navy rounded-tr-none font-black' : 'bg-white text-navy rounded-tl-none font-medium'
                  }`}>
                    {msg.text}
                  </div>
                </div>
              ))}
            </div>

            <div className="flex space-x-2 overflow-x-auto hide-scrollbar py-3">
              {["What are pool hours?", "Guest policy?", "Pet rules?", "Golf dress code?"].map(hint => (
                <button 
                  key={hint}
                  onClick={() => handleSendMessage(hint)}
                  className="px-3 py-1.5 bg-gold border border-black rounded-full text-[10px] font-black text-navy uppercase tracking-widest whitespace-nowrap hover:bg-goldPressed transition-all shadow-sm"
                >
                  {hint}
                </button>
              ))}
            </div>

            <div className="p-2 bg-white border border-black rounded-2xl flex items-center space-x-2 shadow-xl">
              <input 
                type="text" 
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Ask a community question..." 
                className="flex-1 bg-transparent border-none focus:outline-none px-2 py-2 text-sm font-medium"
              />
              <button 
                onClick={() => handleSendMessage()}
                className="p-2 bg-gold text-navy rounded-xl hover:bg-goldPressed border border-black transition-all shadow-md active:scale-95"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
            </div>
            <p className="text-[10px] text-slate-400 mt-2 text-center uppercase tracking-widest font-black">Official Resident Knowledge Base</p>
          </div>
        );

      case 'notifications':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <SectionHeader title="Notifications" subtitle="Stay updated" />
              <button onClick={markAllRead} className="text-[10px] font-black text-navy uppercase tracking-widest hover:text-gold transition-colors">Clear All Unread</button>
            </div>
            <div className="space-y-3">
              {notifications.length === 0 ? (
                <div className="py-20 text-center text-slate-400">
                  <div className="mx-auto mb-4 opacity-20"><ICONS.Bell /></div>
                  <p className="mt-2 text-sm font-bold uppercase tracking-widest">No notifications</p>
                </div>
              ) : (
                notifications.map(notif => (
                  <Card key={notif.id} className={`flex items-start space-x-4 transition-all border border-black shadow-sm ${!notif.read ? 'border-l-[6px] border-l-navy bg-gold/10' : ''}`}>
                    <div className={`p-3 rounded-xl shadow-sm border border-black ${notif.type === 'event' ? 'bg-gold text-navy' : 'bg-navy text-white'}`}>
                      {notif.type === 'event' ? <ICONS.Calendar /> : <ICONS.Announcement />}
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between items-center mb-1">
                        <h4 className="font-bold text-navy uppercase tracking-tight">{notif.title}</h4>
                        <span className="text-[10px] text-slate-400 uppercase font-black">Now</span>
                      </div>
                      <p className="text-xs text-bodyText leading-relaxed font-medium">{notif.message}</p>
                    </div>
                  </Card>
                ))
              )}
            </div>
          </div>
        );

      case 'admin':
        if (!adminAuth) {
          return (
            <div className="max-w-md mx-auto py-20 text-center">
              <Title>Admin Login</Title>
              <Card className="shadow-2xl py-10 border border-black">
                <form onSubmit={(e) => {
                  e.preventDefault();
                  const code = (new FormData(e.currentTarget)).get('pass') as string;
                  if (code === ADMIN_PASSCODE) setAdminAuth(true);
                  else alert('Wrong passcode');
                }}>
                  <input name="pass" type="password" placeholder="Passcode" className="w-full p-4 rounded-xl border border-black mb-4 text-center focus:ring-2 focus:ring-navy outline-none text-xl font-bold tracking-widest" />
                  <Button className="w-full h-14 text-lg">Unlock Dashboard</Button>
                </form>
              </Card>
            </div>
          );
        }
        return (
          <div className="space-y-6">
             <SectionHeader title="Admin Dashboard" subtitle="Community Management" />
             <div className="grid grid-cols-2 gap-4">
                {[
                  { label: 'Broadcast', icon: ICONS.Bell, action: () => alert("Notification sent") },
                  { label: 'Knowledge', icon: ICONS.Chat, action: () => alert("Knowledge updated") },
                  { label: 'Events', icon: ICONS.Calendar, action: () => setActivePage('events') },
                  { label: 'Moderate', icon: ICONS.Announcement, action: () => alert("No reports") }
                ].map(item => (
                  <Card key={item.label} className="py-8 flex flex-col items-center text-center cursor-pointer bg-gold border border-black hover:bg-goldPressed transition-all shadow-sm active:scale-95" onClick={item.action}>
                    <div className="text-navy mb-3 scale-110"><item.icon /></div>
                    <span className="font-black text-navy text-xs uppercase tracking-widest">{item.label}</span>
                    <button className="text-[9px] text-navy font-black mt-3 uppercase tracking-widest opacity-60">Manage →</button>
                  </Card>
                ))}
             </div>
             <Button variant="outline" className="w-full mt-10 h-12" onClick={() => setAdminAuth(false)}>Exit Admin Session</Button>
          </div>
        );

      default:
        return <div>Page coming soon...</div>;
    }
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <Layout activePage={activePage} setActivePage={setActivePage} isGated={isGated} unreadCount={unreadCount}>
      {renderContent()}

      {/* Persistent Floating AI Concierge Bubble - Hidden on AI section */}
      {activePage !== 'ai' && !isGated && (
        <div className="fixed bottom-24 right-4 md:bottom-28 md:right-8 z-[60] flex flex-col items-end">
          {/* Pop-out Chat Interface */}
          {isPopoutOpen && (
            <div className="mb-4 w-72 h-96 bg-white rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.2)] border border-black overflow-hidden flex flex-col animate-fadeIn">
              {/* Pop-out Header - STRICT NAVY BLUE (#0F2233) */}
              <div className="bg-navy p-4 flex justify-between items-center shadow-md border-b border-black">
                <div className="flex items-center space-x-2">
                  <div className="w-8 h-8 bg-white rounded-full flex items-center justify-center border border-black overflow-hidden shadow-sm">
                    <img src="/brand/logo.png" alt="Polo Park East Logo" className="w-full h-full object-contain p-0.5" />
                  </div>
                  <span className="text-white text-[10px] font-black uppercase tracking-widest">Resident Concierge</span>
                </div>
                <button onClick={() => setIsPopoutOpen(false)} className="text-white/60 hover:text-white transition-colors p-1 bg-white/10 rounded-full">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              {/* Pop-out Body - Last 10 messages */}
              <div ref={popoutScrollRef} className="flex-1 overflow-y-auto p-4 space-y-3 hide-scrollbar bg-bgMain">
                {messages.slice(-10).map(msg => (
                  <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[90%] px-3 py-2 rounded-2xl text-[11px] shadow-sm border border-black leading-relaxed ${
                      msg.sender === 'user' ? 'bg-gold text-navy rounded-tr-none font-black' : 'bg-white text-navy rounded-tl-none font-medium'
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                ))}
              </div>

              {/* Pop-out Footer */}
              <div className="p-2 bg-white border-t border-black flex items-center space-x-2">
                <input 
                  type="text" 
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                  placeholder="Ask a question..." 
                  className="flex-1 bg-transparent text-[10px] px-2 py-1.5 focus:outline-none font-bold"
                />
                <button onClick={() => handleSendMessage()} className="p-1.5 bg-gold text-navy rounded-lg hover:bg-goldPressed transition-colors shadow-sm border border-black active:scale-90">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 12h14M12 5l7 7-7 7" /></svg>
                </button>
              </div>
            </div>
          )}

          {/* Main Bubble Button */}
          <button 
            onClick={() => setIsPopoutOpen(!isPopoutOpen)}
            className="w-14 h-14 bg-white rounded-full shadow-[0_8px_30px_rgb(0,0,0,0.12)] flex items-center justify-center hover:scale-110 active:scale-95 transition-all group relative border-2 border-black overflow-hidden"
          >
            {isPopoutOpen ? (
               <svg className="w-6 h-6 text-navy" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7" /></svg>
            ) : (
              <div className="relative w-full h-full flex items-center justify-center">
                <img src="/brand/logo.png" alt="Polo Park East Logo" className="w-full h-full object-contain p-1.5" />
                {/* Notification Indicator */}
                <div className="absolute top-1 right-1 w-4 h-4 bg-red-500 border border-black rounded-full animate-pulse shadow-md" />
              </div>
            )}
          </button>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { PageType, ChatMessage, AppNotification, NotificationSettings } from './types';
import Layout from './components/Layout';
import { Card, Button, Title, GoldBadge, SectionHeader } from './components/UI';
import { ICONS, MOCK_ANNOUNCEMENTS, MOCK_EVENTS, MOCK_AMENITIES, MOCK_RESIDENTS, MOCK_FORUM, COMMUNITY_CODE, ADMIN_PASSCODE, MOCK_FAQS, MOCK_RULES } from './constants';
import { chatWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageType>('home');
  const [isGated, setIsGated] = useState<boolean>(!localStorage.getItem('ppe_auth'));
  const [adminAuth, setAdminAuth] = useState<boolean>(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'ai', text: 'Hello! I am your Polo Park East Concierge. How can I help you today?', timestamp: new Date() }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isPopoutOpen, setIsPopoutOpen] = useState(false);
  const popoutScrollRef = useRef<HTMLDivElement>(null);

  // Notification State
  const [notifications, setNotifications] = useState<AppNotification[]>([
    { id: '1', title: 'New Event!', message: 'Pickleball Mixer has been added for next Saturday.', type: 'event', timestamp: new Date(), read: false },
    { id: '2', title: 'Maintenance Alert', message: 'Pool closing reminder for Oct 10th.', type: 'announcement', timestamp: new Date(), read: false }
  ]);
  const [notifSettings, setNotifSettings] = useState<NotificationSettings>({
    announcements: true,
    events: true,
    messages: false
  });

  // Auto-scroll for chat
  useEffect(() => {
    if (activePage === 'ai') {
      const el = document.getElementById('chat-scroll');
      if (el) el.scrollTop = el.scrollHeight;
    }
    if (isPopoutOpen && popoutScrollRef.current) {
      popoutScrollRef.current.scrollTop = popoutScrollRef.current.scrollHeight;
    }
  }, [messages, activePage, isPopoutOpen]);

  const handleGate = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const code = (new FormData(e.currentTarget)).get('code') as string;
    if (code.toLowerCase() === COMMUNITY_CODE.toLowerCase()) {
      localStorage.setItem('ppe_auth', 'true');
      setIsGated(false);
    } else {
      alert('Invalid Community Code');
    }
  };

  const handleSendMessage = async (text: string = inputValue) => {
    const messageToSend = text.trim();
    if (!messageToSend) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), sender: 'user', text: messageToSend, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');

    const response = await chatWithAI(messageToSend);
    const aiMsg: ChatMessage = { id: (Date.now() + 1).toString(), sender: 'ai', text: response, timestamp: new Date() };
    setMessages(prev => [...prev, aiMsg]);
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  if (isGated && activePage !== 'home') {
    return (
      <div className="min-h-screen bg-navy flex items-center justify-center p-6 text-center">
        <Card className="max-w-md w-full py-10 shadow-2xl border border-black">
          <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mx-auto mb-8 border border-black overflow-hidden shadow-md">
            <img src="/brand/logo.png" alt="Polo Park East Logo" className="w-full h-full object-contain" />
          </div>
          <Title>Residents Only</Title>
          <p className="mb-8 text-sm text-bodyText leading-relaxed px-4">Please enter the resident code to access the Polo Park East community portal.</p>
          <form onSubmit={handleGate} className="space-y-4 px-6">
            <input 
              name="code"
              type="text" 
              placeholder="Enter Resident Code" 
              className="w-full px-4 py-3 rounded-xl border border-black focus:outline-none focus:ring-2 focus:ring-gold text-center tracking-wide text-lg font-bold"
            />
            <Button className="w-full py-4 text-lg">Enter Portal</Button>
            <button onClick={() => setIsGated(false)} className="text-xs text-slate-400 mt-4 block mx-auto underline hover:text-gold transition-colors">Go Back to Public Website</button>
          </form>
        </Card>
      </div>
    );
  }

  const renderContent = () => {
    switch (activePage) {
      case 'home':
        return (
          <div className="space-y-8 animate-fadeIn pb-12">
            <div className="relative rounded-3xl overflow-hidden h-48 md:h-64 mb-8 group shadow-lg border border-black">
              <img src="/brand/entrance.jpg" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="Polo Park East Entrance" />
              <div className="absolute inset-0 bg-gradient-to-t from-navy/90 via-navy/30 to-transparent flex flex-col justify-end p-6">
                <h2 className="text-3xl md:text-4xl text-white font-bold mb-1 shadow-sm">Welcome Home</h2>
                <p className="text-gold font-black uppercase tracking-widest text-xs shadow-sm">Polo Park East Golf & Country Club</p>
              </div>
            </div>

            <SectionHeader title="QUICK ACTIONS" />
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {[
                { label: 'Tee Times', icon: ICONS.Golf, page: 'amenities', color: 'text-emerald-700' },
                { label: 'Neighbors', icon: ICONS.User, page: 'directory', color: 'text-blue-700' },
                { label: 'Event RSVP', icon: ICONS.Calendar, page: 'events', color: 'text-amber-700' },
                { label: 'Concierge', icon: ICONS.Chat, page: 'ai', color: 'text-indigo-700' }
              ].map((item, i) => (
                <Card 
                  key={i} 
                  onClick={() => setActivePage(item.page as PageType)} 
                  className="flex flex-col items-center justify-center py-8 bg-gold border border-black hover:translate-y-[-2px] transition-all group active:scale-95 shadow-sm"
                >
                  <div className={`${item.color} mb-3 scale-125 group-hover:scale-150 transition-transform duration-300 drop-shadow-sm`}>
                    <item.icon />
                  </div>
                  <span className="text-[10px] font-black text-navy uppercase tracking-widest text-center px-1">{item.label}</span>
                </Card>
              ))}
            </div>

            <SectionHeader title="LATEST ANNOUNCEMENTS" subtitle="Stay updated with the community" />
            <div className="space-y-4">
              {MOCK_ANNOUNCEMENTS.map(item => (
                <Card key={item.id} className="relative overflow-hidden group hover:border-black transition-all">
                  {item.isPinned && <div className="absolute top-0 left-0 w-1.5 h-full bg-navy" />}
                  <div className="flex justify-between items-start mb-2">
                    <GoldBadge>{item.category}</GoldBadge>
                    <span className="text-[10px] text-slate-400 font-medium">{item.date}</span>
                  </div>
                  <h3 className="text-lg font-bold text-navy mb-2 group-hover:text-gold transition-colors">{item.title}</h3>
                  <p className="text-sm text-bodyText line-clamp-2">{item.content}</p>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'events':
        return (
          <div className="space-y-6">
            <SectionHeader title="UPCOMING EVENTS" subtitle="Find your next community gathering" />
            <div className="flex space-x-2 overflow-x-auto hide-scrollbar pb-2">
              {['All', 'Social', 'Sports', 'Meeting'].map(cat => (
                <button key={cat} className="px-4 py-2 rounded-full border border-black bg-white text-xs font-black uppercase tracking-widest text-navy hover:bg-gold transition-colors shadow-sm">
                  {cat}
                </button>
              ))}
            </div>
            <div className="space-y-4">
              {MOCK_EVENTS.map(event => (
                <Card key={event.id} className="flex flex-col md:flex-row gap-6 hover:border-black transition-all group">
                  <div className="md:w-32 flex flex-col items-center justify-center bg-gold rounded-xl p-4 text-navy border border-black shadow-sm group-hover:scale-105 transition-transform">
                    <span className="text-sm font-bold uppercase">{event.date.split('-')[1]}</span>
                    <span className="text-3xl font-black">{event.date.split('-')[2]}</span>
                    <span className="text-[10px] font-bold uppercase mt-1">{event.time}</span>
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between items-start mb-1">
                      <h3 className="text-xl font-bold text-navy">{event.title}</h3>
                      <GoldBadge>{event.category}</GoldBadge>
                    </div>
                    <p className="text-sm text-bodyText mb-4">{event.description}</p>
                    <div className="flex items-center space-x-4 text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">
                      <div className="flex items-center"><ICONS.Location /> <span className="ml-1.5">{event.location}</span></div>
                      <div className="flex items-center"><ICONS.User /> <span className="ml-1.5">{event.rsvps}/{event.capacity} Attending</span></div>
                    </div>
                    <div className="flex space-x-2">
                      <Button className="flex-1">RSVP Yes</Button>
                      <Button variant="outline" className="flex-1">Maybe</Button>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'amenities':
        return (
          <div className="space-y-6">
            <SectionHeader title="AMENITIES & FACILITIES" subtitle="Available to all residents" />
            <div className="grid grid-cols-1 gap-6">
              {MOCK_AMENITIES.map(amenity => (
                <Card key={amenity.id} className="p-0 overflow-hidden hover:border-black transition-all">
                  <img src={amenity.image} className="w-full h-48 object-cover border-b border-black" />
                  <div className="p-6">
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xl font-bold text-navy">{amenity.name}</h3>
                      <div className="p-3 bg-gold rounded-full text-navy border border-black shadow-sm"><ICONS.Golf /></div>
                    </div>
                    <div className="grid grid-cols-2 gap-4 mb-4">
                      <div className="p-3 bg-bgMain rounded-xl border border-black">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Hours</span>
                        <p className="text-sm text-navy font-bold">{amenity.hours}</p>
                      </div>
                      <div className="p-3 bg-bgMain rounded-xl border border-black">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Access</span>
                        <p className="text-sm text-navy font-bold">Resident Key Fob</p>
                      </div>
                    </div>
                    <div className="bg-goldTint p-4 rounded-xl border border-black">
                       <span className="text-[10px] font-black text-navy uppercase tracking-widest block mb-3 text-goldPressed">Facility Rules</span>
                        <ul className="grid grid-cols-1 md:grid-cols-2 gap-2">
                          {amenity.rules.map((rule, idx) => (
                            <li key={idx} className="text-xs text-bodyText flex items-center">
                              <div className="w-1.5 h-1.5 rounded-full bg-navy mr-3 flex-shrink-0" /> {rule}
                            </li>
                          ))}
                        </ul>
                    </div>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        );

      case 'directory':
        return (
          <div className="space-y-6">
            <SectionHeader title="RESIDENT DIRECTORY" subtitle="Connect with your neighbors" />
            <div className="relative">
              <input 
                type="text" 
                placeholder="Search residents by name or interest..." 
                className="w-full pl-12 pr-4 py-3 rounded-xl border border-black bg-white focus:outline-none focus:ring-1 focus:ring-gold shadow-sm font-medium"
              />
              <div className="absolute left-4 top-1/2 -translate-y-1/2 text-navy"><ICONS.Search /></div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {MOCK_RESIDENTS.map(res => (
                <Card key={res.id} className="flex items-center space-x-4 hover:border-black transition-all">
                  <div className="relative">
                    <img src={res.avatar} className="w-16 h-16 rounded-2xl object-cover shadow-sm border border-black" />
                    <div className="absolute -bottom-1 -right-1 bg-gold text-navy text-[8px] font-black px-1.5 py-0.5 rounded-md shadow-md border border-black">
                      {res.points} PTS
                    </div>
                  </div>
                  <div className="flex-1">
                    <h3 className="text-lg font-bold text-navy leading-none mb-1">{res.name}</h3>
                    <p className="text-xs text-slate-400 font-medium mb-2">{res.interests.join(' • ')}</p>
                    <div className="flex space-x-2">
                      <Button variant="outline" className="px-3 py-1 text-[10px] h-8">Message</Button>
                      <Button variant="outline" className="px-3 py-1 text-[10px] h-8">Profile</Button>
                    </div>
                  </div>
                  <div className={`w-2.5 h-2.5 rounded-full border border-black ${res.messagingEnabled ? 'bg-green-400' : 'bg-slate-200'}`} />
                </Card>
              ))}
            </div>

            <SectionHeader title="PREFERENCES" subtitle="Notification controls" />
            <Card className="space-y-4 border border-black shadow-inner bg-bgMain/50">
              {(['announcements', 'events', 'messages'] as const).map((key) => (
                <div key={key} className="flex items-center justify-between py-2 border-b border-black last:border-0">
                  <span className="text-sm font-black text-navy uppercase tracking-widest">{key} Notifications</span>
                  <button 
                    onClick={() => setNotifSettings(prev => ({ ...prev, [key]: !prev[key] }))}
                    className={`w-12 h-6 rounded-full relative transition-colors border border-black ${notifSettings[key] ? 'bg-gold' : 'bg-slate-200'}`}
                  >
                    <div className={`absolute top-0.5 w-4 h-4 bg-white rounded-full transition-all shadow-sm border border-black ${notifSettings[key] ? 'left-[26px]' : 'left-0.5'}`} />
                  </button>
                </div>
              ))}
            </Card>
          </div>
        );

      case 'forum':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <SectionHeader title="COMMUNITY FORUM" />
              <Button onClick={() => alert("Write mode enabled. Posting gated by community code.")}>New Post</Button>
             </div>
             <div className="space-y-4">
                {MOCK_FORUM.map(topic => (
                  <Card key={topic.id} className="hover:border-black transition-all border border-black group">
                    <div className="flex justify-between items-start mb-2">
                      <GoldBadge>{topic.category}</GoldBadge>
                      <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest">{topic.lastActivity}</span>
                    </div>
                    <h3 className="text-lg font-bold text-navy mb-1 group-hover:text-goldPressed transition-colors">{topic.title}</h3>
                    <div className="flex justify-between items-center text-xs text-bodyText">
                      <span className="font-medium">Started by {topic.author}</span>
                      <div className="flex items-center space-x-1.5"><ICONS.Chat /><span className="text-[10px] font-black uppercase text-navy tracking-widest">{topic.replies} REPLIES</span></div>
                    </div>
                  </Card>
                ))}
             </div>
          </div>
        );

      case 'ai':
        return (
          <div className="flex flex-col h-[calc(100vh-200px)] animate-fadeIn">
            <SectionHeader title="CONCIERGE AI" subtitle="Ask about community life" />
            <div id="chat-scroll" className="flex-1 overflow-y-auto space-y-4 pb-4 pr-2 hide-scrollbar">
              {messages.map(msg => (
                <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-sm shadow-sm border border-black ${
                    msg.sender === 'user' ? 'bg-gold text-navy rounded-tr-none font-black' : 'bg-white text-navy rounded-tl-none font-medium'
                  }`}>
                    {msg.text}
                  </div>
                </div>
              ))}
            </div>

            <div className="flex space-x-2 overflow-x-auto hide-scrollbar py-3">
              {["What are pool hours?", "Guest policy?", "Pet rules?", "Golf dress code?"].map(hint => (
                <button 
                  key={hint}
                  onClick={() => handleSendMessage(hint)}
                  className="px-3 py-1.5 bg-gold border border-black rounded-full text-[10px] font-black text-navy uppercase tracking-widest whitespace-nowrap hover:bg-goldPressed transition-all shadow-sm"
                >
                  {hint}
                </button>
              ))}
            </div>

            <div className="p-2 bg-white border border-black rounded-2xl flex items-center space-x-2 shadow-xl">
              <input 
                type="text" 
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                placeholder="Ask a community question..." 
                className="flex-1 bg-transparent border-none focus:outline-none px-2 py-2 text-sm font-medium"
              />
              <button 
                onClick={() => handleSendMessage()}
                className="p-2 bg-gold text-navy rounded-xl hover:bg-goldPressed border border-black transition-all shadow-md active:scale-95"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
            </div>
            <p className="text-[10px] text-slate-400 mt-2 text-center uppercase tracking-widest font-black">Official Resident Knowledge Base</p>
          </div>
        );

      case 'notifications':
        return (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <SectionHeader title="NOTIFICATIONS" subtitle="Stay updated" />
              <button onClick={markAllRead} className="text-[10px] font-black text-navy uppercase tracking-widest hover:text-gold transition-colors">Clear All Unread</button>
            </div>
            <div className="space-y-3">
              {notifications.length === 0 ? (
                <div className="py-20 text-center text-slate-400">
                  <div className="mx-auto mb-4 opacity-20"><ICONS.Bell /></div>
                  <p className="mt-2 text-sm font-bold uppercase tracking-widest">No notifications</p>
                </div>
              ) : (
                notifications.map(notif => (
                  <Card key={notif.id} className={`flex items-start space-x-4 transition-all border border-black shadow-sm ${!notif.read ? 'border-l-[6px] border-l-navy bg-gold/10' : ''}`}>
                    <div className={`p-3 rounded-xl shadow-sm border border-black ${notif.type === 'event' ? 'bg-gold text-navy' : 'bg-navy text-white'}`}>
                      {notif.type === 'event' ? <ICONS.Calendar /> : <ICONS.Announcement />}
                    </div>
                    <div className="flex-1">
                      <div className="flex justify-between items-center mb-1">
                        <h4 className="font-bold text-navy uppercase tracking-tight">{notif.title}</h4>
                        <span className="text-[10px] text-slate-400 uppercase font-black">Now</span>
                      </div>
                      <p className="text-xs text-bodyText leading-relaxed font-medium">{notif.message}</p>
                    </div>
                  </Card>
                ))
              )}
            </div>
          </div>
        );

      case 'admin':
        if (!adminAuth) {
          return (
            <div className="max-w-md mx-auto py-20 text-center">
              <Title>Admin Login</Title>
              <Card className="shadow-2xl py-10 border border-black">
                <form onSubmit={(e) => {
                  e.preventDefault();
                  const code = (new FormData(e.currentTarget)).get('pass') as string;
                  if (code === ADMIN_PASSCODE) setAdminAuth(true);
                  else alert('Wrong passcode');
                }}>
                  <input name="pass" type="password" placeholder="Passcode" className="w-full p-4 rounded-xl border border-black mb-4 text-center focus:ring-2 focus:ring-navy outline-none text-xl font-bold tracking-widest" />
                  <Button className="w-full h-14 text-lg">Unlock Dashboard</Button>
                </form>
              </Card>
            </div>
          );
        }
        return (
          <div className="space-y-6">
             <SectionHeader title="ADMIN DASHBOARD" subtitle="Community Management" />
             <div className="grid grid-cols-2 gap-4">
                {[
                  { label: 'Broadcast', icon: ICONS.Bell, action: () => alert("Notification sent") },
                  { label: 'Knowledge', icon: ICONS.Chat, action: () => alert("Knowledge updated") },
                  { label: 'Events', icon: ICONS.Calendar, action: () => setActivePage('events') },
                  { label: 'Moderate', icon: ICONS.Announcement, action: () => alert("No reports") }
                ].map(item => (
                  <Card key={item.label} className="py-8 flex flex-col items-center text-center cursor-pointer bg-gold border border-black hover:bg-goldPressed transition-all shadow-sm active:scale-95" onClick={item.action}>
                    <div className="text-navy mb-3 scale-110"><item.icon /></div>
                    <span className="font-black text-navy text-xs uppercase tracking-widest">{item.label}</span>
                    <button className="text-[9px] text-navy font-black mt-3 uppercase tracking-widest opacity-60">Manage →</button>
                  </Card>
                ))}
             </div>
             <Button variant="outline" className="w-full mt-10 h-12" onClick={() => setAdminAuth(false)}>Exit Admin Session</Button>
          </div>
        );

      default:
        return <div>Page coming soon...</div>;
    }
  };

  const unreadCount = notifications.filter(n => !n.read).length;

  return (
    <Layout activePage={activePage} setActivePage={setActivePage} isGated={isGated} unreadCount={unreadCount}>
      {renderContent()}

      {/* Persistent Floating AI Concierge Bubble - Hidden on AI section */}
      {activePage !== 'ai' && !isGated && (
        <div className="fixed bottom-24 right-4 md:bottom-28 md:right-8 z-[60] flex flex-col items-end">
          {/* Pop-out Chat Interface */}
          {isPopoutOpen && (
            <div className="mb-4 w-72 h-96 bg-white rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.2)] border border-black overflow-hidden flex flex-col animate-fadeIn">
              {/* Pop-out Header - STRICT NAVY BLUE (#0F2233) */}
              <div className="bg-navy p-4 flex justify-between items-center shadow-md border-b border-black">
                <div className="flex items-center space-x-2">
                  <div className="w-8 h-8 bg-white rounded-full flex items-center justify-center border border-black overflow-hidden shadow-sm">
                    <img src="/brand/logo.png" alt="Polo Park East Logo" className="w-full h-full object-contain p-0.5" />
                  </div>
                  <span className="text-white text-[10px] font-black uppercase tracking-widest">Resident Concierge</span>
                </div>
                <button onClick={() => setIsPopoutOpen(false)} className="text-white/60 hover:text-white transition-colors p-1 bg-white/10 rounded-full">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              {/* Pop-out Body - Last 10 messages */}
              <div ref={popoutScrollRef} className="flex-1 overflow-y-auto p-4 space-y-3 hide-scrollbar bg-bgMain">
                {messages.slice(-10).map(msg => (
                  <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[90%] px-3 py-2 rounded-2xl text-[11px] shadow-sm border border-black leading-relaxed ${
                      msg.sender === 'user' ? 'bg-gold text-navy rounded-tr-none font-black' : 'bg-white text-navy rounded-tl-none font-medium'
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                ))}
              </div>

              {/* Pop-out Footer */}
              <div className="p-2 bg-white border-t border-black flex items-center space-x-2">
                <input 
                  type="text" 
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                  placeholder="Ask a question..." 
                  className="flex-1 bg-transparent text-[10px] px-2 py-1.5 focus:outline-none font-bold"
                />
                <button onClick={() => handleSendMessage()} className="p-1.5 bg-gold text-navy rounded-lg hover:bg-goldPressed transition-colors shadow-sm border border-black active:scale-90">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M5 12h14M12 5l7 7-7 7" /></svg>
                </button>
              </div>
            </div>
          )}

          {/* Main Bubble Button */}
          <button 
            onClick={() => setIsPopoutOpen(!isPopoutOpen)}
            className="w-14 h-14 bg-white rounded-full shadow-[0_8px_30px_rgb(0,0,0,0.12)] flex items-center justify-center hover:scale-110 active:scale-95 transition-all group relative border-2 border-black overflow-hidden"
          >
            {isPopoutOpen ? (
               <svg className="w-6 h-6 text-navy" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7" /></svg>
            ) : (
              <div className="relative w-full h-full flex items-center justify-center">
                <img src="/brand/logo.png" alt="Polo Park East Logo" className="w-full h-full object-contain p-1.5" />
                {/* Notification Indicator */}
                <div className="absolute top-1 right-1 w-4 h-4 bg-red-500 border border-black rounded-full animate-pulse shadow-md" />
              </div>
            )}
          </button>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { PageType, ChatMessage, AppNotification, NotificationSettings } from './types';
import Layout from './components/Layout';
import { Card, Button, Title, GoldBadge, SectionHeader } from './components/UI';
import { ICONS, MOCK_ANNOUNCEMENTS, MOCK_EVENTS, MOCK_AMENITIES, MOCK_RESIDENTS, MOCK_FORUM, COMMUNITY_CODE, ADMIN_PASSCODE, MOCK_FAQS, MOCK_RULES } from './constants';
import { chatWithAI } from './services/geminiService';

const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageType>('home');
  const [isGated, setIsGated] = useState<boolean>(!localStorage.getItem('ppe_auth'));
  const [adminAuth, setAdminAuth] = useState<boolean>(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'ai', text: 'Hello! I am your Polo Park East Concierge. How can I help you today?', timestamp: new Date() }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isPopoutOpen, setIsPopoutOpen] = useState(false);
  const popoutScrollRef = useRef<HTMLDivElement>(null);

  // Notification State
  const [notifications, setNotifications] = useState<AppNotification[]>([
    { id: '1', title: 'New Event!', message: 'Pickleball Mixer has been added for next Saturday.', type: 'event', timestamp: new Date(), read: false },
    { id: '2', title: 'Maintenance Alert', message: 'Pool closing reminder for Oct 10th.', type: 'announcement', timestamp: new Date(), read: false }
  ]);
  const [notifSettings, setNotifSettings] = useState<NotificationSettings>({
    announcements: true,
    events: true,
    messages: false
  });

  // Auto-scroll for chat
  useEffect(() => {
    if (activePage === 'ai') {
      const el = document.getElementById('chat-scroll');
      if (el) el.scrollTop = el.scrollHeight;
    }
    if (isPopoutOpen && popoutScrollRef.current) {
      popoutScrollRef.current.scrollTop = popoutScrollRef.current.scrollHeight;
    }
  }, [messages, activePage, isPopoutOpen]);

  const handleGate = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const code = (new FormData(e.currentTarget)).get('code') as string;
    if (code.toLowerCase() === COMMUNITY_CODE.toLowerCase()) {
      localStorage.setItem('ppe_auth', 'true');
      setIsGated(false);
    } else {
      alert('Invalid Community Code');
    }
  };

  const handleSendMessage = async (text: string = inputValue) => {
    const messageToSend = text.trim();
    if (!messageToSend) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), sender: 'user', text: messageToSend, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');

    const response = await chatWithAI(messageToSend);
    const aiMsg: ChatMessage = { id: (Date.now() + 1).toString(), sender: 'ai', text: response, timestamp: new Date() };
    setMessages(prev => [...prev, aiMsg]);
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, read: true })));
  };

  if (isGated && activePage !== 'home') {
    return (
      <div className="min-h-screen bg-navy flex items-center justify-center p-6 text-center">
        <Card className="max-w-md w-full py-10 shadow-2xl border border-black bg-gold">
          <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center mx-auto mb-8 border border-black overflow-hidden shadow-md">
            <img src="/brand/logo.png" alt="Polo Park East Logo" className="w-full h-full object-contain" />
          </div>
          <Title className="text-navy">Residents Only</Title>
          <p className="mb-8 text-sm text-navy/80 leading-relaxed px-4 font-medium">Please enter the resident code to access the Polo Park East community portal.</p>
          <form onSubmit={handleGate} className="space-y-4 px-6">
            <input 
              name="code"
              type="text" 
              placeholder="Enter Resident Code" 
              className="w-full px-4 py-3 rounded-xl border border-black focus:outline-none focus:ring-2 focus:ring-navy text-center tracking-wide text-lg font-bold bg-white"
            />
            <Button variant="secondary" className="w-full py-4 text-lg">Enter Portal</Button>
            <button onClick={() => setIsGated(false)} className="text-xs text-navy/60 mt-4 block mx-auto underline hover:text-navy transition-colors font-bold">Go Back to Public Website</button>
          </form>
        </Card>
      </div>
    );
  }

  const renderContent = () => {
    switch (activePage) {
      case 'home':
        return (
          <div className="space-y-8 animate-fadeIn pb-12">
            <div className="relative rounded-3xl overflow-hidden h-48 md:h-64 mb-8 group shadow-lg border border-black">
              <img src="/brand/entrance.jpg" className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="Polo Park East Entrance" />
              <div className="absolute inset-0 bg-gradient-to-t from-navy/90 via-navy/30 to-transparent flex flex-col justify-end p-6">
                <h2 className="text-3xl md:text-4xl text-white font-bold mb-1 shadow-sm">Welcome Home</h2>
                <p className="text-gold font-black uppercase tracking-widest text-xs shadow-sm">Polo Park East Golf & Country Club</p>
              </div>
            </div>

            <SectionHeader title="QUICK ACTIONS" />
