const App: React.FC = () => {
  const [activePage, setActivePage] = useState<PageType>('home');
  const [isGated, setIsGated] = useState<boolean>(!localStorage.getItem('ppe_auth'));
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'ai', text: 'Welcome to Polo Park East. How can I help you today?', timestamp: new Date() }
  ]);
  const [inputValue, setInputValue] = useState('');

  const handleGate = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const code = (new FormData(e.currentTarget)).get('code') as string;
    if (code.toLowerCase() === COMMUNITY_CODE.toLowerCase()) {
      localStorage.setItem('ppe_auth', 'true');
      setIsGated(false);
    } else {
      alert('Invalid Community Code');
    }
  };

  const handleSendMessage = async (text: string = inputValue) => {
    const messageToSend = text.trim();
    if (!messageToSend) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), sender: 'user', text: messageToSend, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');

    const response = await chatWithAI(messageToSend);
    const aiMsg: ChatMessage = { id: (Date.now() + 1).toString(), sender: 'ai', text: response, timestamp: new Date() };
    setMessages(prev => [...prev, aiMsg]);
  };

  if (isGated && activePage !== 'home') {
    return (
      <div className="min-h-screen bg-tan flex items-center justify-center p-6">
        <BubbleTile className="max-w-md w-full py-12 text-center">
          <div className="w-20 h-20 bg-navy rounded-full flex items-center justify-center mx-auto mb-8 border-4 border-gold overflow-hidden">
            <img src="/brand/logo.png" alt="Logo" className="w-12 h-12 object-contain" />
          </div>
          <Title>Resident Login</Title>
          <p className="mb-8 text-sm text-bodyText leading-relaxed px-4">Access restricted to Polo Park East residents. Please enter your community code.</p>
          <form onSubmit={handleGate} className="space-y-4 px-4">
            <input 
              name="code"
              type="text" 
              placeholder="Enter Code" 
              className="w-full px-4 py-4 rounded-2xl border border-border bg-[#F8FAFC] focus:outline-none focus:ring-2 focus:ring-gold text-center tracking-widest text-lg font-bold"
            />
            <Button className="w-full py-4">Enter Community</Button>
            <button onClick={() => setIsGated(false)} className="text-[10px] font-black uppercase text-bodyText/40 mt-4 tracking-widest">Return to Public Site</button>
          </form>
