  const renderContent = () => {
    switch (activePage) {
      case 'home':
        return (
          <div className="space-y-8 animate-fadeIn pb-12">
            <div className="relative rounded-bubble overflow-hidden h-40 md:h-64 shadow-lg border border-white">
              <img src="/brand/entrance.jpg" className="w-full h-full object-cover" alt="Entrance" />
