                  <p className="text-xs text-bodyText line-clamp-2 leading-relaxed font-medium">{item.content}</p>
                </BubbleTile>
              ))}
            </div>
          </div>
        );

      case 'events':
        return (
          <div className="space-y-6">
            <SectionHeader title="Community Events" />
            {MOCK_EVENTS.map(event => (
              <BubbleTile key={event.id} className="p-0 overflow-hidden">
                <div className="flex flex-col md:flex-row">
                  <div className="md:w-32 bg-navy p-6 flex flex-col items-center justify-center text-center">
                    <span className="text-gold text-3xl font-black leading-none">{event.date.split('-')[2]}</span>
