      case 'amenities':
        return (
          <div className="space-y-6">
            <SectionHeader title="Our Amenities" />
            <div className="grid grid-cols-1 gap-6">
              {MOCK_AMENITIES.map(amenity => (
                <BubbleTile key={amenity.id} className="p-0 overflow-hidden">
                  <img src={amenity.image} className="w-full h-48 object-cover border-b border-border" />
                  <div className="p-6">
                    <div className="flex items-center justify-between mb-4">
                      <h3 className="text-xl font-bold text-heading">{amenity.name}</h3>
                      <div className="bg-gold p-3 rounded-full text-navy"><ICONS.Golf /></div>
                    </div>
                    <div className="grid grid-cols-2 gap-4 mb-4">
                      <div className="p-4 bg-tan/20 rounded-2xl border border-border">
