      case 'forum':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <SectionHeader title="Community Forum" />
              <Button onClick={() => alert("Write mode enabled")}>Post</Button>
             </div>
             <div className="space-y-4">
                {MOCK_FORUM.map(topic => (
