              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
            </div>
          </div>
        );

      default:
        return <div className="p-12 text-center text-navy/20 font-black uppercase tracking-widest">Coming Soon</div>;
    }
  };

  return (
    <Layout activePage={activePage} setActivePage={setActivePage} isGated={isGated} unreadCount={0}>
      {renderContent()}
    </Layout>
  );
};

