  const [aiMessages, setAiMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'ai', text: 'Welcome to Polo Park East. How can I help you today?', timestamp: new Date() }
  ]);
  const [aiInputValue, setAiInputValue] = useState('');
  const [branding, setBranding] = useState<{ logo: string | null, hero: string | null }>({ logo: null, hero: null });
  const [toast, setToast] = useState<{ show: boolean, msg: string }>({ show: false, msg: '' });

