import { chatWithAI } from './services/geminiService';
import { generateCommunityImages } from './services/imageService';
import { db } from './services/database';

const App: React.FC = () => {
  // Navigation State
  const [activePage, setActivePage] = useState<PageType>('home');

  // Persistence Data
  const [announcements, setAnnouncements] = useState<Announcement[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [forum, setForum] = useState<ForumTopic[]>([]);
  const [residents, setResidents] = useState<Resident[]>([]);
  const [userRsvps, setUserRsvps] = useState<RSVPStatus[]>([]);
  const [directMessages, setDirectMessages] = useState<ChatMessage[]>([]);

  // UI State
  const [isPopoutOpen, setIsPopoutOpen] = useState(false);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiMessages, setAiMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'ai', text: 'Welcome to Polo Park East. How can I help you today?', timestamp: new Date() }
  ]);
  const [aiInputValue, setAiInputValue] = useState('');
  const [branding, setBranding] = useState<{ logo: string | null, hero: string | null }>({ logo: null, hero: null });
  const [toast, setToast] = useState<{ show: boolean, msg: string }>({ show: false, msg: '' });

  // Drill-down states
  const [selectedTopic, setSelectedTopic] = useState<ForumTopic | null>(null);
  const [selectedResident, setSelectedResident] = useState<Resident | null>(null);
  const [searchQuery, setSearchQuery] = useState('');

  // Modals
  const [isPostModalOpen, setIsPostModalOpen] = useState(false);
  const [isAnnModalOpen, setIsAnnModalOpen] = useState(false);
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);

  const popoutScrollRef = useRef<HTMLDivElement>(null);
  const mainChatScrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    db.init();
    refreshData();
    loadBranding();
  }, []);

  useEffect(() => {
    if (isPopoutOpen && popoutScrollRef.current) {
      popoutScrollRef.current.scrollTop = popoutScrollRef.current.scrollHeight;
    }
  }, [aiMessages, isPopoutOpen]);

  useEffect(() => {
    if (activePage === 'ai' && mainChatScrollRef.current) {
      mainChatScrollRef.current.scrollTop = mainChatScrollRef.current.scrollHeight;
    }
  }, [aiMessages, activePage]);

  const refreshData = () => {
    setAnnouncements(db.getAnnouncements());
    setEvents(db.getEvents());
    setForum(db.getForum());
    setResidents(db.getResidents());
    setUserRsvps(db.getUserRSVPs());
    setDirectMessages(db.getMessages());
  };

  const loadBranding = async () => {
    const [logoUrl, heroUrl] = await Promise.all([
      generateCommunityImages("An elegant minimalist circular logo for 'Polo Park East' golf community, deep navy and gold, white background, featuring a subtle golf motif."),
      generateCommunityImages("A high-quality photographic landscape image for 'Polo Park East 55+ Golf Community', showing lush green golf fairways and luxury homes under a bright blue Florida sky, cinematic lighting, 16:9 aspect ratio.")
    ]);
    setBranding({ logo: logoUrl, hero: heroUrl });
  };

  const showToast = (msg: string) => setToast({ show: true, msg });

  const handleRSVP = (eventId: string, status: 'yes' | 'no' | 'maybe') => {
    const currentStatus = userRsvps.find(r => r.eventId === eventId)?.status || null;
    if (currentStatus === status) return;
    const { events: updatedEvents, rsvps: updatedRsvps } = db.updateEventRSVP(eventId, currentStatus, status);
    setEvents(updatedEvents);
    setUserRsvps(updatedRsvps);
    showToast(`RSVP updated to ${status.toUpperCase()}`);
  };

  const handleCreateTopic = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newTopic: ForumTopic = {
      id: Date.now().toString(),
      title: formData.get('title') as string,
      content: formData.get('content') as string,
      author: 'Current Resident',
      replies: [],
      lastActivity: 'Just now',
      category: formData.get('category') as string
    };
    db.saveTopic(newTopic);
    refreshData();
    setIsPostModalOpen(false);
    showToast("Forum topic posted successfully!");
  };

  const handleReply = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const content = (new FormData(e.currentTarget)).get('reply') as string;
    if (!content.trim() || !selectedTopic) return;
    db.saveReply(selectedTopic.id, {
      id: Date.now().toString(),
      author: 'Current Resident',
      content,
      timestamp: new Date().toISOString()
    });
    refreshData();
    e.currentTarget.reset();
    const updatedForum = db.getForum();
    setSelectedTopic(updatedForum.find(t => t.id === selectedTopic.id) || null);
    showToast("Reply sent.");
  };

  const handleSendDirectMessage = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const text = (new FormData(e.currentTarget)).get('text') as string;
    if (!text.trim() || !selectedResident) return;
    const msg: ChatMessage = {
      id: Date.now().toString(),
      sender: 'user',
      receiverId: selectedResident.id,
      text,
      timestamp: new Date()
    };
    db.sendMessage(msg);
    refreshData();
    e.currentTarget.reset();
  };

  const handleAiChat = async (text: string, isPopout: boolean) => {
    const messageToSend = text.trim();
    if (!messageToSend || isAiLoading) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), sender: 'user', text: messageToSend, timestamp: new Date() };
    setAiMessages(prev => [...prev, userMsg]);
    setAiInputValue('');
    setIsAiLoading(true);

    const contextData = {
      announcements,
      events,
      amenities: MOCK_AMENITIES,
      faqs: MOCK_FAQS,
      rules: MOCK_RULES
    };

    const response = await chatWithAI(messageToSend, contextData);
    const aiMsg: ChatMessage = { id: (Date.now() + 1).toString(), sender: 'ai', text: response, timestamp: new Date() };
    setAiMessages(prev => [...prev, aiMsg]);
    setIsAiLoading(false);
  };

  const openMessaging = (res: Resident) => {
    if (!res.messagingEnabled) {
      showToast(`${res.name} has messaging disabled.`);
      return;
    }
    setSelectedResident(res);
    setActivePage('messaging');
  };

  const openTopic = (topic: ForumTopic) => {
    setSelectedTopic(topic);
    setActivePage('forum_detail');
  };

  const renderContent = () => {
    switch (activePage) {
      case 'home':
        return (
          <div className="space-y-8 animate-fadeIn pb-12">
            <div className="relative rounded-bubble overflow-hidden h-44 md:h-64 shadow-xl border-4 border-white">
              {!branding.hero ? (
                <div className="w-full h-full bg-navy animate-pulse flex items-center justify-center">
                  <span className="text-white/20 font-black uppercase tracking-widest text-xs">Generating Luxury...</span>
                </div>
              ) : (
                <ImageWithFallback src={branding.hero} className="w-full h-full object-cover" alt="Home Hero" />
              )}
              <div className="absolute inset-0 bg-gradient-to-t from-navy/90 via-navy/40 to-transparent flex flex-col justify-end p-6">
                <h2 className="text-2xl text-white font-bold mb-1">Welcome Home</h2>
                <p className="text-gold font-black uppercase tracking-widest text-[9px] drop-shadow-md">Polo Park East Golf & Country Club</p>
              </div>
            </div>

            <SectionHeader title="Quick Actions" />
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {[
                { label: 'Announcements', icon: ICONS.Bell, page: 'home' },
                { label: 'Events', icon: ICONS.Calendar, page: 'events' },
                { label: 'Amenities', icon: ICONS.Golf, page: 'amenities' },
                { label: 'Directory', icon: ICONS.User, page: 'directory' },
                { label: 'Forum', icon: ICONS.Chat, page: 'forum' },
                { label: 'AI Concierge', icon: ICONS.Settings, page: 'ai' }
              ].map((item, i) => (
                <BubbleTile key={i} onClick={() => setActivePage(item.page as PageType)} className="flex flex-col items-center justify-center py-6 h-40 aspect-square mx-auto w-full max-w-[160px]">
                  <div className="bg-gold p-4 rounded-full text-navy mb-4 shadow-sm flex items-center justify-center"><item.icon /></div>
                  <span className="text-[10px] font-black text-heading uppercase tracking-widest text-center px-1 truncate w-full">{item.label}</span>
                </BubbleTile>
              ))}
            </div>

            <SectionHeader title="Latest News" />
            <div className="space-y-4">
              {announcements.slice(0, 3).map(item => (
                <BubbleTile key={item.id} className="relative overflow-hidden group">
                  <div className="flex justify-between items-start mb-3">
                    <GoldBadge>{item.category}</GoldBadge>
                    <span className="text-[9px] text-bodyText font-black uppercase tracking-widest">{item.date}</span>
                  </div>
                  <h3 className="text-lg font-bold text-heading mb-1 line-clamp-1">{item.title}</h3>
                  <p className="text-xs text-bodyText line-clamp-2 leading-relaxed font-medium">{item.content}</p>
                </BubbleTile>
              ))}
            </div>
          </div>
        );

      case 'events':
        return (
          <div className="space-y-6">
            <SectionHeader title="Community Events" />
            {events.length === 0 && <div className="text-center py-12 text-bodyText/40 uppercase font-black text-[10px] tracking-widest">No upcoming events scheduled</div>}
            {events.map(event => {
              const myRSVP = userRsvps.find(r => r.eventId === event.id)?.status;
              return (
                <BubbleTile key={event.id} className="p-0 overflow-hidden border-none shadow-lg">
                  <div className="flex flex-col md:flex-row">
                    <div className="md:w-32 bg-navy p-6 flex flex-col items-center justify-center text-center shadow-inner">
                      <span className="text-gold text-3xl font-black leading-none">{event.date.split('-')[2] || '??'}</span>
                      <span className="text-white text-[10px] font-black uppercase tracking-widest mt-2">{event.date.split('-')[1] || 'MON'}</span>
                    </div>
                    <div className="flex-1 p-6">
                      <div className="flex justify-between items-start mb-2 gap-2">
                        <h3 className="text-xl font-bold text-heading line-clamp-2 leading-tight">{event.title}</h3>
                        <div className="flex-shrink-0"><GoldBadge>{event.category}</GoldBadge></div>
                      </div>
                      <p className="text-xs text-bodyText mb-5 line-clamp-2 leading-relaxed">{event.description}</p>
                      <div className="flex items-center space-x-6 text-[9px] font-black uppercase tracking-widest text-navy/40 mb-6">
                         <span className="flex items-center"><ICONS.Location /><span className="ml-2 truncate max-w-[100px]">{event.location}</span></span>
                         <span className="flex items-center"><ICONS.User /><span className="ml-2">{event.rsvps} joined</span></span>
                      </div>
                      <div className="grid grid-cols-3 gap-2">
                        <Button variant={myRSVP === 'yes' ? 'primary' : 'outline'} onClick={() => handleRSVP(event.id, 'yes')} className="py-2.5 px-0 text-[8px]">RSVP YES</Button>
                        <Button variant={myRSVP === 'no' ? 'secondary' : 'outline'} onClick={() => handleRSVP(event.id, 'no')} className="py-2.5 px-0 text-[8px]">NO</Button>
                        <Button variant={myRSVP === 'maybe' ? 'primary' : 'outline'} onClick={() => handleRSVP(event.id, 'maybe')} className="py-2.5 px-0 text-[8px]">MAYBE</Button>
                      </div>
                    </div>
                  </div>
                </BubbleTile>
              );
            })}
          </div>
        );

      case 'amenities':
        return (
          <div className="space-y-6">
            <SectionHeader title="Our Amenities" />
            {MOCK_AMENITIES.map(amenity => (
              <BubbleTile key={amenity.id} className="p-0 overflow-hidden border-none shadow-lg">
                <ImageWithFallback src={amenity.image} className="w-full h-48 object-cover" />
                <div className="p-6">
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-xl font-bold text-heading">{amenity.name}</h3>
                    <div className="bg-gold p-3 rounded-full text-navy shadow-md"><ICONS.Golf /></div>
                  </div>
                  <div className="grid grid-cols-2 gap-4 mb-5">
                    <div className="p-4 bg-tan/20 rounded-2xl border border-border">
                      <span className="text-[9px] font-black text-bodyText uppercase tracking-widest block mb-1">Hours</span>
                      <p className="text-xs text-heading font-bold">{amenity.hours}</p>
                    </div>
                    <div className="p-4 bg-tan/20 rounded-2xl border border-border">
                      <span className="text-[9px] font-black text-bodyText uppercase tracking-widest block mb-1">Access</span>
                      <p className="text-xs text-heading font-bold truncate">Resident Fob</p>
                    </div>
                  </div>
                </div>
              </BubbleTile>
            ))}
          </div>
        );

      case 'directory':
        return (
          <div className="space-y-6">
            <SectionHeader title="Resident Directory" />
            <div className="relative mb-6">
              <input type="text" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Search neighbors..." className="w-full pl-12 pr-4 py-4 rounded-2xl border border-border bg-white shadow-inner focus:outline-none focus:ring-1 focus:ring-gold font-medium" />
              <div className="absolute left-4 top-1/2 -translate-y-1/2 text-navy/30"><ICONS.Search /></div>
            </div>
            <div className="grid grid-cols-1 gap-4">
              {residents.filter(r => r.name.toLowerCase().includes(searchQuery.toLowerCase())).map(res => (
                <BubbleTile key={res.id} className="flex items-center space-x-5 shadow-md">
                  <ImageWithFallback src={res.avatar} className="w-14 h-14 rounded-2xl object-cover border border-border shadow-sm" />
                  <div className="flex-1 min-w-0">
                    <h3 className="text-lg font-bold text-heading truncate">{res.name}</h3>
                    <p className="text-[10px] text-bodyText font-medium truncate italic opacity-60">{res.interests.join(', ')}</p>
                  </div>
                  <Button variant="outline" onClick={() => openMessaging(res)} className="px-4 py-2.5 text-[8px] lowercase font-black tracking-widest">message</Button>
                </BubbleTile>
              ))}
            </div>
          </div>
        );

      case 'forum':
        return (
          <div className="space-y-6">
             <div className="flex justify-between items-center">
              <SectionHeader title="Community Forum" />
              <Button onClick={() => setIsPostModalOpen(true)} className="py-2 px-6">New Topic</Button>
             </div>
             <div className="space-y-4">
                {forum.map(topic => (
                  <BubbleTile key={topic.id} onClick={() => openTopic(topic)} className="shadow-md">
                    <div className="flex justify-between items-center mb-2">
                      <GoldBadge>{topic.category}</GoldBadge>
                      <span className="text-[9px] text-bodyText font-black uppercase tracking-widest">{topic.lastActivity}</span>
                    </div>
                    <h3 className="text-lg font-bold text-heading mb-2 line-clamp-2 leading-tight">{topic.title}</h3>
                    <div className="flex items-center justify-between text-[10px] text-bodyText/60 font-black uppercase tracking-widest">
                      <span className="italic font-medium normal-case">by {topic.author}</span>
                      <span className="flex items-center space-x-1.5"><ICONS.Chat /><span className="font-black">{topic.replies?.length || 0} REPLIES</span></span>
                    </div>
                  </BubbleTile>
                ))}
             </div>
          </div>
        );

      case 'forum_detail':
        if (!selectedTopic) return null;
        return (
          <div className="space-y-6 animate-fadeIn">
            <button onClick={() => setActivePage('forum')} className="flex items-center text-[10px] font-black uppercase tracking-widest text-bodyText mb-4 hover:text-navy">
              <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7" /></svg>
              Back to Forum
            </button>
            <BubbleTile className="border-none shadow-xl">
              <div className="flex justify-between items-center mb-4">
                <GoldBadge>{selectedTopic.category}</GoldBadge>
                <span className="text-[9px] font-black uppercase text-bodyText">{selectedTopic.lastActivity}</span>
              </div>
              <h2 className="text-2xl font-bold text-heading mb-4">{selectedTopic.title}</h2>
              <p className="text-sm text-bodyText leading-relaxed mb-6 whitespace-pre-wrap">{selectedTopic.content}</p>
              <div className="text-[10px] font-black uppercase text-navy/40">Posted by {selectedTopic.author}</div>
            </BubbleTile>

            <SectionHeader title={`Replies (${selectedTopic.replies?.length || 0})`} />
            <div className="space-y-4 mb-24">
              {selectedTopic.replies?.map(reply => (
                <BubbleTile key={reply.id} className="bg-[#F8FAFC]">
                  <div className="flex justify-between items-start mb-2">
                    <span className="text-[10px] font-black uppercase text-navy">{reply.author}</span>
                    <span className="text-[8px] font-medium text-bodyText">{new Date(reply.timestamp).toLocaleString()}</span>
                  </div>
                  <p className="text-sm text-bodyText">{reply.content}</p>
                </BubbleTile>
              ))}
              <BubbleTile>
                <form onSubmit={handleReply} className="space-y-3">
                  <textarea name="reply" placeholder="Add a reply..." required className="w-full h-24 p-4 rounded-2xl bg-tan/10 focus:outline-none border border-border text-sm font-medium resize-none" />
                  <div className="flex justify-end"><Button className="py-2">Post Reply</Button></div>
                </form>
              </BubbleTile>
            </div>
          </div>
        );

      case 'messaging':
        if (!selectedResident) return null;
        const chatHistory = directMessages.filter(m => 
          (m.sender === 'user' && m.receiverId === selectedResident.id) ||
          (m.sender === 'resident' && m.id === selectedResident.id)
        );
        return (
          <div className="flex flex-col h-[calc(100vh-220px)] animate-fadeIn">
            <div className="flex items-center space-x-4 mb-6">
              <button onClick={() => setActivePage('directory')} className="p-2 bg-white rounded-full shadow-sm text-bodyText">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15 19l-7-7 7-7" /></svg>
              </button>
              <div className="flex items-center space-x-3">
                <img src={selectedResident.avatar} className="w-10 h-10 rounded-full border-2 border-white shadow-sm" />
                <div>
                  <h3 className="text-lg font-bold text-heading leading-none">{selectedResident.name}</h3>
                  <span className="text-[9px] font-black uppercase tracking-widest text-gold">Active Now</span>
                </div>
              </div>
            </div>
            <div className="flex-1 overflow-y-auto space-y-4 pb-6 hide-scrollbar px-1">
              {chatHistory.length === 0 && <div className="text-center py-10 text-[10px] uppercase font-black text-bodyText/30 tracking-[0.2em]">Start of conversation</div>}
              {chatHistory.map(msg => (
                <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] px-5 py-3 rounded-2xl shadow-md border border-border ${msg.sender === 'user' ? 'bg-navy text-white rounded-tr-none' : 'bg-white text-heading rounded-tl-none'} text-sm leading-relaxed`}>
                    {msg.text}
                  </div>
                </div>
              ))}
            </div>
            <form onSubmit={handleSendDirectMessage} className="p-2 bg-white rounded-bubble border border-border flex items-center space-x-2 shadow-2xl">
              <input name="text" autoComplete="off" placeholder="Type a message..." required className="flex-1 bg-tan/10 rounded-2xl focus:outline-none px-4 py-3.5 text-sm font-medium" />
              <button type="submit" className="p-3.5 bg-gold text-navy rounded-2xl active:opacity-70 shadow-md">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
              </button>
            </form>
          </div>
        );

      case 'ai':
        return (
          <div className="flex flex-col h-[calc(100vh-220px)] animate-fadeIn">
            <SectionHeader title="AI Concierge" subtitle="Ask anything about the community" />
            <div ref={mainChatScrollRef} className="flex-1 overflow-y-auto space-y-4 pb-6 hide-scrollbar px-1">
              {aiMessages.map(msg => (
                <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] px-5 py-3.5 rounded-bubble shadow-md border border-border ${msg.sender === 'user' ? 'bg-navy text-white rounded-tr-none font-bold' : 'bg-white text-heading rounded-tl-none font-medium'} text-sm leading-relaxed`}>
                    {msg.text}
                  </div>
                </div>
              ))}
              {isAiLoading && <div className="flex justify-start"><div className="bg-white px-5 py-3.5 rounded-bubble rounded-tl-none shadow-sm border border-border flex space-x-1"><div className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce" /><div className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce [animation-delay:0.2s]" /><div className="w-1.5 h-1.5 bg-gold rounded-full animate-bounce [animation-delay:0.4s]" /></div></div>}
            </div>
            <div className="p-2 bg-white rounded-bubble border border-border flex items-center space-x-2 shadow-2xl mt-2">
              <input type="text" value={aiInputValue} onChange={(e) => setAiInputValue(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAiChat(aiInputValue, true)} placeholder="Ask about pool hours, tee times..." className="flex-1 bg-tan/10 rounded-2xl focus:outline-none px-4 py-3.5 text-sm font-medium" />
              <button onClick={() => handleAiChat(aiInputValue, true)} disabled={isAiLoading} className="p-3.5 bg-gold text-navy rounded-2xl active:opacity-70 shadow-md disabled:opacity-50"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg></button>
            </div>
          </div>
        );

      case 'admin':
        return (
          <div className="space-y-8 animate-fadeIn">
            <SectionHeader title="Community Admin" subtitle="Manage content and moderation" />
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <BubbleTile onClick={() => setIsAnnModalOpen(true)} className="flex items-center space-x-4 p-8">
                <div className="bg-navy p-4 rounded-full text-gold"><ICONS.Announcement /></div>
                <div><h3 className="font-bold text-heading">Post Announcement</h3><p className="text-xs text-bodyText">Broadcast news to all residents</p></div>
              </BubbleTile>
              <BubbleTile onClick={() => setIsEventModalOpen(true)} className="flex items-center space-x-4 p-8">
                <div className="bg-navy p-4 rounded-full text-gold"><ICONS.Calendar /></div>
                <div><h3 className="font-bold text-heading">Create Event</h3><p className="text-xs text-bodyText">Add new social or sports events</p></div>
              </BubbleTile>
            </div>
            <SectionHeader title="Moderation Queue" />
            <div className="bg-white rounded-bubble p-6 border border-border text-center text-[10px] font-black uppercase text-bodyText/30 tracking-widest">No reports in queue</div>
          </div>
        );

      default:
        return <div className="p-12 text-center text-navy/20 font-black uppercase tracking-widest">Coming Soon</div>;
    }
  };

  return (
    <Layout activePage={activePage} setActivePage={setActivePage} unreadCount={0} logo={branding.logo}>
      {renderContent()}

      {/* Floating Chat Bubble */}
      {activePage !== 'ai' && (
        <div className="fixed bottom-24 right-6 md:bottom-28 md:right-10 z-[60] flex flex-col items-end">
          {isPopoutOpen && (
            <div className="mb-4 w-72 md:w-80 h-[450px] bg-white rounded-[32px] shadow-[0_20px_60px_rgba(0,0,0,0.15)] border border-border overflow-hidden flex flex-col animate-fadeIn">
              <div className="bg-navy p-5 flex justify-between items-center shadow-md">
                <div className="flex items-center space-x-3">
                  <div className="w-8 h-8 bg-white rounded-full flex items-center justify-center border border-gold/40 shadow-sm overflow-hidden"><ImageWithFallback src={branding.logo || "/brand/logo.png"} alt="Logo" className="w-6 h-6 object-contain" /></div>
                  <div><h4 className="text-gold text-[10px] font-black uppercase tracking-widest leading-none">Concierge</h4><span className="text-white/40 text-[8px] font-bold uppercase tracking-widest">Active Now</span></div>
                </div>
                <button onClick={() => setIsPopoutOpen(false)} className="text-white/40 hover:text-white transition-colors"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7" /></svg></button>
              </div>
              <div ref={popoutScrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 bg-[#F8FAFC] hide-scrollbar">
                {aiMessages.map(msg => (
                  <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}><div className={`max-w-[85%] px-4 py-2.5 rounded-2xl text-[11px] shadow-sm border border-border ${msg.sender === 'user' ? 'bg-navy text-white rounded-tr-none font-bold' : 'bg-white text-heading rounded-tl-none font-medium'} leading-relaxed`}>{msg.text}</div></div>
                ))}
                {isAiLoading && <div className="flex justify-start"><div className="bg-white px-4 py-2.5 rounded-2xl rounded-tl-none shadow-sm border border-border flex space-x-1"><div className="w-1 h-1 bg-gold rounded-full animate-bounce" /><div className="w-1 h-1 bg-gold rounded-full animate-bounce [animation-delay:0.2s]" /><div className="w-1 h-1 bg-gold rounded-full animate-bounce [animation-delay:0.4s]" /></div></div>}
              </div>
              <div className="p-3 bg-white border-t border-border flex items-center space-x-2">
                <input type="text" value={aiInputValue} onChange={(e) => setAiInputValue(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleAiChat(aiInputValue, true)} placeholder="Ask a question..." className="flex-1 bg-tan/10 rounded-xl px-4 py-2 text-[11px] font-medium focus:outline-none" />
                <button onClick={() => handleAiChat(aiInputValue, true)} disabled={isAiLoading} className="p-2 bg-gold text-navy rounded-xl shadow-sm active:opacity-70 disabled:opacity-50"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 7l5 5m0 0l-5 5m5-5H6" /></svg></button>
              </div>
            </div>
          )}
          <button onClick={() => setIsPopoutOpen(!isPopoutOpen)} className={`w-14 h-14 rounded-full flex items-center justify-center shadow-2xl transition-all duration-300 transform active:scale-90 ${isPopoutOpen ? 'bg-white text-navy rotate-180 border border-border' : 'bg-navy text-gold'}`}>{isPopoutOpen ? <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg> : <ICONS.Chat />}</button>
        </div>
      )}

      {/* Modals */}
      <Modal isOpen={isPostModalOpen} onClose={() => setIsPostModalOpen(false)} title="Create Forum Topic">
        <form onSubmit={handleCreateTopic} className="space-y-4">
          <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Title</label><input name="title" required placeholder="Question or subject" className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Category</label><select name="category" className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none"><option>General Discussion</option><option>Local Services</option><option>Activity Planning</option><option>Sports</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Content</label><textarea name="content" required placeholder="What's on your mind?" className="w-full px-4 py-3 h-32 rounded-xl border border-border bg-tan/5 focus:outline-none resize-none" /></div>
          <Button className="w-full py-4">Post Topic</Button>
        </form>
      </Modal>

      <Modal isOpen={isAnnModalOpen} onClose={() => setIsAnnModalOpen(false)} title="Post Announcement">
        <form onSubmit={(e) => {
          e.preventDefault();
          const fd = new FormData(e.currentTarget);
          db.saveAnnouncement({
            id: Date.now().toString(),
            title: fd.get('title') as string,
            content: fd.get('content') as string,
            category: fd.get('category') as any,
            date: new Date().toISOString().split('T')[0]
          });
          refreshData();
          setIsAnnModalOpen(false);
          showToast("Announcement published!");
        }} className="space-y-4">
          <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Title</label><input name="title" required className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Category</label><select name="category" className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none"><option>News</option><option>Maintenance</option><option>Board</option></select></div>
          <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Content</label><textarea name="content" required className="w-full px-4 py-3 h-32 rounded-xl border border-border bg-tan/5 focus:outline-none resize-none" /></div>
          <Button className="w-full py-4">Publish Now</Button>
        </form>
      </Modal>

      <Modal isOpen={isEventModalOpen} onClose={() => setIsEventModalOpen(false)} title="Create Community Event">
        <form onSubmit={(e) => {
          e.preventDefault();
          const fd = new FormData(e.currentTarget);
          const newEvent: Event = {
            id: Date.now().toString(),
            title: fd.get('title') as string,
            date: fd.get('date') as string,
            time: fd.get('time') as string,
            location: fd.get('location') as string,
            category: fd.get('category') as any,
            description: fd.get('description') as string,
            capacity: 50,
            rsvps: 0
          };
          db.saveEvent(newEvent);
          refreshData();
          setIsEventModalOpen(false);
          showToast("Event created successfully!");
        }} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Event Title</label><input name="title" required className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none" /></div>
            <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Category</label><select name="category" className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none"><option>Social</option><option>Sports</option><option>Meeting</option></select></div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Date</label><input type="date" name="date" required className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none" /></div>
            <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Time</label><input type="time" name="time" required className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none" /></div>
          </div>
          <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Location</label><input name="location" required className="w-full px-4 py-3 rounded-xl border border-border bg-tan/5 focus:outline-none" /></div>
          <div><label className="block text-[10px] font-black uppercase text-navy/40 mb-1">Description</label><textarea name="description" required className="w-full px-4 py-3 h-24 rounded-xl border border-border bg-tan/5 focus:outline-none resize-none" /></div>
          <Button className="w-full py-4">Create Event</Button>
        </form>
      </Modal>

      <Toast visible={toast.show} message={toast.msg} onHide={() => setToast({ show: false, msg: '' })} />
    </Layout>
  );
};

export default App;

